{
  "name": "One-Session Pharmacy (Ultra-Fast POS)",
  "description": "A high-performance pharmacy management system optimized for low-latency inventory control and point-of-sale operations, featuring offline-first capabilities and medical-grade UI.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Medicine {
  id?: number;
  name: string;
  barcode: string;
  price: number;
  stock: number;
  category: string;
  expiryDate: string;
}

export interface Sale {
  id?: number;
  totalAmount: number;
  timestamp: number;
  itemsJson: string; // JSON string for fast storage
}

export type ViewType = 'inventory' | 'reports';

import Dexie, { Table } from 'dexie';
import { Medicine, Sale } from './types';

export class PharmacyDB extends Dexie {
  medicines!: Table<Medicine>;
  sales!: Table<Sale>;

  constructor() {
    super('PharmacyDB');
    this.version(1).stores({
      medicines: '++id, name, barcode, stock, expiryDate',
      sales: '++id, timestamp'
    });
  }
}

export const db = new PharmacyDB();

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Search, Plus, Package, BarChart3, Edit2, AlertCircle, Share2, X, Save, Trash2 } from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType } from './types';

// Helper: Format Date
const formatDate = (date: string) => new Date(date).toLocaleDateString('ar-EG');

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('inventory');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Fetch data
  const loadData = useCallback(async () => {
    const all = await db.medicines.toArray();
    setMedicines(all);
  }, []);

  useEffect(() => {
    loadData();
    if (searchInputRef.current) {
        searchInputRef.current.focus();
    }
  }, [loadData]);

  // Fast filtering
  const filteredMedicines = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return medicines.filter(m => 
        m.name.toLowerCase().includes(q) || 
        m.barcode.toLowerCase().includes(q)
    );
  }, [medicines, searchQuery]);

  // Stats for Reports
  const stats = useMemo(() => {
    const totalValue = medicines.reduce((sum, m) => sum + (m.price * m.stock), 0);
    const lowStockCount = medicines.filter(m => m.stock < 5).length;
    const expiredCount = medicines.filter(m => new Date(m.expiryDate) < new Date()).length;
    return { totalValue, lowStockCount, expiredCount };
  }, [medicines]);

  const handleSave = async (data: Medicine) => {
    if (data.id) {
      await db.medicines.update(data.id, data);
    } else {
      await db.medicines.add(data);
    }
    setIsDialogOpen(false);
    setEditingMedicine(null);
    loadData();
  };

  const handleDelete = async (id: number) => {
    if (confirm('هل أنت متأكد من الحذف؟')) {
      await db.medicines.delete(id);
      loadData();
      setIsDialogOpen(false);
      setEditingMedicine(null);
    }
  };

  const shareToWhatsApp = () => {
    const lowStock = medicines.filter(m => m.stock < 10);
    let message = "طلبية صيدلية (عجز مخزون):\n";
    lowStock.forEach(m => {
      message += `- ${m.name}: مطلوب [ ] (الحالي: ${m.stock})\n`;
    });
    const url = `https://wa.me/?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Search Header */}
      <header className="bg-emerald-600 p-4 shadow-lg flex-shrink-0">
        <div className="relative">
          <input
            ref={searchInputRef}
            type="text"
            placeholder="بحث سريع (اسم أو باركود)..."
            className="w-full bg-white text-emerald-950 rounded-xl py-3 px-11 text-lg font-semibold shadow-inner focus:ring-4 focus:ring-emerald-300 transition-all"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <Search className="absolute left-3 top-3.5 text-emerald-400" size={24} />
          {searchQuery && (
            <button 
                onClick={() => setSearchQuery('')}
                className="absolute right-3 top-3.5 text-gray-400"
            >
                <X size={24} />
            </button>
          )}
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-grow overflow-y-auto dense-list p-2 bg-emerald-50">
        {view === 'inventory' ? (
          <div className="space-y-2">
            {filteredMedicines.length > 0 ? (
              filteredMedicines.map((med) => (
                <div 
                  key={med.id}
                  onClick={() => { setEditingMedicine(med); setIsDialogOpen(true); }}
                  className="bg-white border-b border-emerald-100 p-3 rounded-xl flex justify-between items-center active:bg-emerald-100 transition-colors shadow-sm"
                >
                  <div className="flex-grow">
                    <h3 className="font-bold text-lg text-emerald-900 leading-tight">{med.name}</h3>
                    <div className="flex gap-3 text-xs text-emerald-600 mt-1 font-medium">
                      <span>{med.barcode}</span>
                      <span className={new Date(med.expiryDate) < new Date() ? 'text-red-500 font-bold' : ''}>
                        تنتهي: {formatDate(med.expiryDate)}
                      </span>
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="text-xl font-bold text-emerald-700">{med.price.toFixed(2)} ج.م</div>
                    <div className={`text-sm font-bold ${med.stock < 5 ? 'text-red-500' : 'text-emerald-500'}`}>
                      المخزون: {med.stock}
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="flex flex-col items-center justify-center py-20 text-emerald-300">
                <Package size={64} className="mb-4 opacity-20" />
                <p className="text-lg">لا توجد نتائج للبحث</p>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-4 p-2">
            <h2 className="text-2xl font-bold text-emerald-900 mb-4">تقارير الجرد السريع</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="bg-white p-6 rounded-2xl shadow-sm border-r-8 border-emerald-500">
                <p className="text-emerald-600 font-semibold mb-1">إجمالي قيمة المخزون</p>
                <p className="text-3xl font-black text-emerald-900">{stats.totalValue.toLocaleString()} <span className="text-sm font-normal">ج.م</span></p>
              </div>
              <div className="bg-white p-6 rounded-2xl shadow-sm border-r-8 border-orange-500">
                <p className="text-orange-600 font-semibold mb-1">نقص المخزون (&lt;5)</p>
                <p className="text-3xl font-black text-orange-900">{stats.lowStockCount}</p>
              </div>
              <div className="bg-white p-6 rounded-2xl shadow-sm border-r-8 border-red-500">
                <p className="text-red-600 font-semibold mb-1">أدوية منتهية الصلاحية</p>
                <p className="text-3xl font-black text-red-900">{stats.expiredCount}</p>
              </div>
            </div>

            <button 
              onClick={shareToWhatsApp}
              className="w-full bg-emerald-600 text-white flex items-center justify-center gap-3 py-4 rounded-2xl font-bold text-xl shadow-lg active:scale-95 transition-transform"
            >
              <Share2 size={24} />
              إرسال النواقص إلى واتساب
            </button>
          </div>
        )}
      </main>

      {/* Bottom Navigation */}
      <nav className="bg-white border-t border-emerald-100 flex justify-around p-3 pb-6 flex-shrink-0 shadow-[0_-4px_10px_rgba(0,0,0,0.05)]">
        <button 
          onClick={() => setView('inventory')}
          className={`flex flex-col items-center gap-1 transition-colors ${view === 'inventory' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Package size={24} />
          <span className="text-xs font-bold">المخزون</span>
        </button>
        <div className="relative -mt-8">
            <button 
                onClick={() => { setEditingMedicine(null); setIsDialogOpen(true); }}
                className="bg-emerald-500 text-white p-5 rounded-full shadow-xl shadow-emerald-200 active:scale-90 transition-transform"
            >
                <Plus size={32} strokeWidth={3} />
            </button>
        </div>
        <button 
          onClick={() => setView('reports')}
          className={`flex flex-col items-center gap-1 transition-colors ${view === 'reports' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <BarChart3 size={24} />
          <span className="text-xs font-bold">التقارير</span>
        </button>
      </nav>

      {/* Fast Add/Edit Dialog */}
      {isDialogOpen && (
        <MedicineDialog 
          initialData={editingMedicine} 
          onSave={handleSave} 
          onClose={() => setIsDialogOpen(false)}
          onDelete={handleDelete}
        />
      )}
    </div>
  );
};

// Internal Sub-component for performance & scoping
const MedicineDialog: React.FC<{
  initialData: Medicine | null;
  onSave: (data: Medicine) => void;
  onClose: () => void;
  onDelete: (id: number) => void;
}> = ({ initialData, onSave, onClose, onDelete }) => {
  const [formData, setFormData] = useState<Medicine>(
    initialData || { name: '', barcode: '', price: 0, stock: 0, category: 'عام', expiryDate: new Date().toISOString().split('T')[0] }
  );

  const nameRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (nameRef.current) nameRef.current.focus();
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.name && formData.price >= 0) {
      onSave(formData);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-3xl overflow-hidden shadow-2xl">
        <div className="bg-emerald-600 p-4 text-white flex justify-between items-center">
          <h2 className="text-xl font-bold">{initialData ? 'تعديل دواء' : 'إضافة دواء جديد'}</h2>
          <button onClick={onClose}><X size={24}/></button>
        </div>
        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-bold text-emerald-900 mb-1">اسم الدواء</label>
            <input 
              ref={nameRef}
              type="text" 
              className="w-full border-2 border-emerald-100 rounded-xl p-3 focus:border-emerald-500"
              value={formData.name}
              required
              onChange={e => setFormData({...formData, name: e.target.value})}
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-bold text-emerald-900 mb-1">السعر (ج.م)</label>
              <input 
                type="number" 
                step="0.01"
                className="w-full border-2 border-emerald-100 rounded-xl p-3 focus:border-emerald-500"
                value={formData.price}
                required
                onChange={e => setFormData({...formData, price: parseFloat(e.target.value) || 0})}
              />
            </div>
            <div>
              <label className="block text-sm font-bold text-emerald-900 mb-1">الكمية</label>
              <input 
                type="number" 
                className="w-full border-2 border-emerald-100 rounded-xl p-3 focus:border-emerald-500"
                value={formData.stock}
                required
                onChange={e => setFormData({...formData, stock: parseInt(e.target.value) || 0})}
              />
            </div>
          </div>
          <div>
            <label className="block text-sm font-bold text-emerald-900 mb-1">الباركود</label>
            <input 
              type="text" 
              className="w-full border-2 border-emerald-100 rounded-xl p-3 focus:border-emerald-500"
              value={formData.barcode}
              onChange={e => setFormData({...formData, barcode: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-emerald-900 mb-1">تاريخ انتهاء الصلاحية</label>
            <input 
              type="date" 
              className="w-full border-2 border-emerald-100 rounded-xl p-3 focus:border-emerald-500"
              value={formData.expiryDate}
              onChange={e => setFormData({...formData, expiryDate: e.target.value})}
            />
          </div>

          <div className="pt-4 flex gap-2">
            <button 
              type="submit" 
              className="flex-grow bg-emerald-600 text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-transform"
            >
              <Save size={20} />
              حفظ المعلومات
            </button>
            {initialData?.id && (
              <button 
                type="button"
                onClick={() => onDelete(initialData.id!)}
                className="bg-red-50 text-red-500 p-4 rounded-xl active:scale-95 transition-transform"
              >
                <Trash2 size={24} />
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default App;

import { Dexie, Table } from 'dexie';
import { Medicine, Sale } from './types';

export class PharmacyDB extends Dexie {
  medicines!: Table<Medicine>;
  sales!: Table<Sale>;

  constructor() {
    super('PharmacyDB');
    // Fix: Using the named import { Dexie } ensures that the 'version' method 
    // is correctly recognized as a member of the base class.
    this.version(1).stores({
      medicines: '++id, name, barcode, stock, expiryDate',
      sales: '++id, timestamp'
    });
  }
}

export const db = new PharmacyDB();

export interface Medicine {
  id?: number;
  name: string;
  barcode: string;
  price: number;
  stock: number;
  category: string;
  expiryDate: string;
}

export interface Sale {
  id?: number;
  totalAmount: number;
  timestamp: number; // milliseconds
  itemsJson: string; // List of {name, price, quantity}
}

export interface CartItem {
  medicine: Medicine;
  quantity: number;
}

export type ViewType = 'pos' | 'accounting';

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Search, Plus, Package, BarChart3, ShoppingCart, X, Save, Trash2, CheckCircle2, History, TrendingUp, AlertCircle } from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem } from './types';

const formatDate = (date: string) => new Date(date).toLocaleDateString('ar-EG');
const formatTime = (ts: number) => new Date(ts).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' });

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('pos');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map());
  const [isEditOpen, setIsEditOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [checkoutResult, setCheckoutResult] = useState<{status: 'success' | 'error', msg: string} | null>(null);
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Load Data
  const loadData = useCallback(async () => {
    const [allMeds, allSales] = await Promise.all([
      db.medicines.toArray(),
      db.sales.orderBy('timestamp').reverse().toArray()
    ]);
    setMedicines(allMeds);
    setSalesHistory(allSales);
  }, []);

  useEffect(() => {
    loadData();
    if (searchInputRef.current) searchInputRef.current.focus();
  }, [loadData]);

  // POS Actions
  const addToCart = (med: Medicine) => {
    if (med.stock <= 0) {
      setCheckoutResult({status: 'error', msg: 'عذراً، الدواء غير متوفر في المخزون'});
      setTimeout(() => setCheckoutResult(null), 2000);
      return;
    }

    // Check current cart quantity vs stock
    const currentInCart = cart.get(med.id!)?.quantity || 0;
    if (currentInCart >= med.stock) {
        setCheckoutResult({status: 'error', msg: 'الكمية المختارة تتجاوز المخزون'});
        setTimeout(() => setCheckoutResult(null), 2000);
        return;
    }

    const newCart = new Map(cart);
    newCart.set(med.id!, { medicine: med, quantity: currentInCart + 1 });
    setCart(newCart);

    // Haptic Feedback
    if (navigator.vibrate) navigator.vibrate(50);
  };

  const removeFromCart = (id: number) => {
    const newCart = new Map(cart);
    const item = newCart.get(id);
    if (item && item.quantity > 1) {
      newCart.set(id, { ...item, quantity: item.quantity - 1 });
    } else {
      newCart.delete(id);
    }
    setCart(newCart);
  };

  const handleCheckout = async () => {
    if (cart.size === 0) return;

    try {
      const items = Array.from(cart.values());
      const total = items.reduce((sum, item) => sum + (item.medicine.price * item.quantity), 0);

      // Atomic updates
      await db.transaction('rw', db.medicines, db.sales, async () => {
        for (const item of items) {
          const med = await db.medicines.get(item.medicine.id!);
          if (!med || med.stock < item.quantity) throw new Error(`Stock mismatch for ${item.medicine.name}`);
          await db.medicines.update(item.medicine.id!, { stock: med.stock - item.quantity });
        }

        await db.sales.add({
          totalAmount: total,
          timestamp: Date.now(),
          itemsJson: JSON.stringify(items.map(i => ({ name: i.medicine.name, qty: i.quantity, price: i.medicine.price })))
        });
      });

      setCart(new Map());
      setCheckoutResult({status: 'success', msg: `تمت العملية بنجاح! الإجمالي: ${total.toFixed(2)}`});
      loadData();
    } catch (err: any) {
      setCheckoutResult({status: 'error', msg: 'خطأ في العملية: ' + err.message});
    }
    setTimeout(() => setCheckoutResult(null), 3000);
  };

  // Accounting Logic
  const todayStats = useMemo(() => {
    const startOfDay = new Date().setHours(0, 0, 0, 0);
    const todaySales = salesHistory.filter(s => s.timestamp >= startOfDay);
    const total = todaySales.reduce((sum, s) => sum + s.totalAmount, 0);
    return { count: todaySales.length, total, history: todaySales };
  }, [salesHistory]);

  const filteredMedicines = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return medicines.filter(m => m.name.toLowerCase().includes(q) || m.barcode.toLowerCase().includes(q));
  }, [medicines, searchQuery]);

  // Inventory Logic
  const handleSaveMedicine = async (data: Medicine) => {
    if (data.id) await db.medicines.update(data.id, data);
    else await db.medicines.add(data);
    setIsEditOpen(false);
    setEditingMedicine(null);
    loadData();
  };

  const handleDeleteMedicine = async (id: number) => {
    if (confirm('حذف الدواء نهائياً؟')) {
      await db.medicines.delete(id);
      setIsEditOpen(false);
      loadData();
    }
  };

  const cartTotal = Array.from(cart.values()).reduce((sum, item) => sum + (item.medicine.price * item.quantity), 0);
  const cartItemsCount = Array.from(cart.values()).reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-emerald-50 text-emerald-950 select-none">
      {/* Search Header - Fixed */}
      <header className="bg-emerald-600 p-4 shadow-lg flex-shrink-0 z-20">
        <div className="relative">
          <input
            ref={searchInputRef}
            type="text"
            placeholder="ابحث وبع فوراً (اسم أو باركود)..."
            className="w-full bg-white text-emerald-950 rounded-2xl py-4 px-12 text-lg font-bold shadow-inner focus:ring-4 focus:ring-emerald-300 transition-all border-none"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <Search className="absolute left-4 top-4.5 text-emerald-400" size={24} />
          {searchQuery && (
            <button onClick={() => setSearchQuery('')} className="absolute right-4 top-4.5 text-gray-300">
                <X size={24} />
            </button>
          )}
        </div>
      </header>

      {/* Main View Area */}
      <main className="flex-grow overflow-y-auto dense-list p-2 pb-32">
        {view === 'pos' ? (
          <div className="grid grid-cols-1 gap-2">
            {filteredMedicines.map((med) => (
              <div 
                key={med.id}
                onClick={() => addToCart(med)}
                onContextMenu={(e) => { e.preventDefault(); setEditingMedicine(med); setIsEditOpen(true); }}
                className={`bg-white border-2 ${cart.has(med.id!) ? 'border-emerald-500 bg-emerald-50/50' : 'border-transparent'} p-4 rounded-2xl flex justify-between items-center active:scale-[0.98] transition-all shadow-sm cursor-pointer`}
              >
                <div className="flex-grow">
                  <div className="flex items-center gap-2">
                    <h3 className="font-black text-xl text-emerald-900">{med.name}</h3>
                    {cart.has(med.id!) && (
                        <span className="bg-emerald-600 text-white text-xs px-2 py-0.5 rounded-full font-bold">
                            في السلة: {cart.get(med.id!)?.quantity}
                        </span>
                    )}
                  </div>
                  <div className="flex gap-4 mt-1">
                    <span className="text-xs font-bold text-emerald-600 bg-emerald-100 px-2 py-0.5 rounded-lg">
                        {med.barcode}
                    </span>
                    <span className={`text-xs font-bold ${med.stock < 5 ? 'text-red-500' : 'text-emerald-500'}`}>
                        المخزون: {med.stock}
                    </span>
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-2xl font-black text-emerald-700">{med.price.toFixed(2)}</div>
                  <div className="text-[10px] font-bold text-emerald-400 uppercase">ج.م</div>
                </div>
              </div>
            ))}
            {filteredMedicines.length === 0 && (
                <div className="py-20 text-center opacity-30 flex flex-col items-center">
                    <Package size={80} />
                    <p className="text-xl font-bold mt-4">لا يوجد نتائج</p>
                </div>
            )}
          </div>
        ) : (
          <div className="space-y-4 animate-in fade-in duration-300">
            <div className="grid grid-cols-2 gap-3">
               <div className="bg-white p-5 rounded-3xl shadow-sm border-b-4 border-emerald-500">
                  <div className="flex items-center gap-2 text-emerald-600 mb-1">
                    <TrendingUp size={18}/>
                    <span className="font-bold text-sm">مبيعات اليوم</span>
                  </div>
                  <div className="text-3xl font-black text-emerald-900">{todayStats.total.toFixed(2)}</div>
               </div>
               <div className="bg-white p-5 rounded-3xl shadow-sm border-b-4 border-emerald-400">
                  <div className="flex items-center gap-2 text-emerald-600 mb-1">
                    <History size={18}/>
                    <span className="font-bold text-sm">عدد الفواتير</span>
                  </div>
                  <div className="text-3xl font-black text-emerald-900">{todayStats.count}</div>
               </div>
            </div>

            <h3 className="text-xl font-black text-emerald-900 mt-6 flex items-center gap-2">
