import Dexie, { Table } from 'dexie';
import { Medicine, Sale } from './types';

// Extend Dexie to create our PharmacyDB class with strictly typed tables
export class PharmacyDB extends Dexie {
  medicines!: Table<Medicine>;
  sales!: Table<Sale>;

  constructor() {
    super('PharmacyDB');
    // Configure database schema version and store definitions
    // Fixing inheritance issue where 'version' might not be recognized on the instance correctly
    this.version(1).stores({
      medicines: '++id, name, barcode, stock, expiryDate',
      sales: '++id, timestamp'
    });
  }
}

export const db = new PharmacyDB();

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Search, Plus, Package, BarChart3, ShoppingCart, X, Save, Trash2, CheckCircle2, History, TrendingUp, AlertCircle } from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem } from './types';

const formatDate = (date: string) => new Date(date).toLocaleDateString('ar-EG');
const formatTime = (ts: number) => new Date(ts).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' });

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('pos');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  // Explicitly typing the Map and providing initial state with types
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map<number, CartItem>());
  const [isEditOpen, setIsEditOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [checkoutResult, setCheckoutResult] = useState<{status: 'success' | 'error', msg: string} | null>(null);
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Load Data
  const loadData = useCallback(async () => {
    const [allMeds, allSales] = await Promise.all([
      db.medicines.toArray(),
      db.sales.orderBy('timestamp').reverse().toArray()
    ]);
    setMedicines(allMeds);
    setSalesHistory(allSales);
  }, []);

  useEffect(() => {
    loadData();
    if (searchInputRef.current) searchInputRef.current.focus();
  }, [loadData]);

  // POS Actions
  const addToCart = (med: Medicine) => {
    if (med.stock <= 0) {
      setCheckoutResult({status: 'error', msg: 'عذراً، الدواء غير متوفر في المخزون'});
      setTimeout(() => setCheckoutResult(null), 2000);
      return;
    }

    // Check current cart quantity vs stock
    const currentInCart = cart.get(med.id!)?.quantity || 0;
    if (currentInCart >= med.stock) {
        setCheckoutResult({status: 'error', msg: 'الكمية المختارة تتجاوز المخزون'});
        setTimeout(() => setCheckoutResult(null), 2000);
        return;
    }

    const newCart = new Map<number, CartItem>(cart);
    newCart.set(med.id!, { medicine: med, quantity: currentInCart + 1 });
    setCart(newCart);

    // Haptic Feedback
    if (navigator.vibrate) navigator.vibrate(50);
  };

  const removeFromCart = (id: number) => {
    const newCart = new Map<number, CartItem>(cart);
    // Adding explicit type assertion for cart item retrieval
    const item = newCart.get(id) as CartItem | undefined;
    if (item && item.quantity > 1) {
      newCart.set(id, { ...item, quantity: item.quantity - 1 } as CartItem);
    } else {
      newCart.delete(id);
    }
    setCart(newCart);
  };

  const handleCheckout = async () => {
    if (cart.size === 0) return;

    try {
      // Adding explicit type assertion for cart values array
      const items = Array.from(cart.values()) as CartItem[];
      const total = items.reduce((sum, item) => sum + (item.medicine.price * item.quantity), 0);

      // Perform atomic database transaction to update stock and add sale record
      await db.transaction('rw', db.medicines, db.sales, async () => {
        for (const item of items) {
          const med = await db.medicines.get(item.medicine.id!);
          if (!med || med.stock < item.quantity) throw new Error(`Stock mismatch for ${item.medicine.name}`);
          await db.medicines.update(item.medicine.id!, { stock: med.stock - item.quantity });
        }

        await db.sales.add({
          totalAmount: total,
          timestamp: Date.now(),
          itemsJson: JSON.stringify(items.map(i => ({ name: i.medicine.name, qty: i.quantity, price: i.medicine.price })))
        });
      });

      setCart(new Map<number, CartItem>());
      setCheckoutResult({status: 'success', msg: `تمت العملية بنجاح! الإجمالي: ${total.toFixed(2)}`});
      loadData();
    } catch (err: any) {
      setCheckoutResult({status: 'error', msg: 'خطأ في العملية: ' + err.message});
    }
    setTimeout(() => setCheckoutResult(null), 3000);
  };

