      await db.medicines.delete(id);
      setIsEditOpen(false);
      loadData();
    }
  };

  // Adding explicit type assertions for cart calculations to avoid 'unknown' errors
  const cartTotal = (Array.from(cart.values()) as CartItem[]).reduce((sum, item) => sum + (item.medicine.price * item.quantity), 0);
