        <div className="bg-emerald-600 p-6 text-white flex justify-between items-center">
          <h2 className="text-2xl font-black">{initialData ? 'تعديل المخزون' : 'إضافة دواء'}</h2>
          <button onClick={onClose} className="p-2 bg-emerald-700/50 rounded-full"><X size={24}/></button>
        </div>
        <form onSubmit={(e) => { e.preventDefault(); onSave(formData); }} className="p-8 space-y-5">
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900 block px-1">الاسم التجاري</label>
            <input 
              ref={nameRef}
              type="text" 
              className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 focus:bg-white transition-all outline-none"
              value={formData.name}
              required
              onChange={e => setFormData({...formData, name: e.target.value})}
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-sm font-black text-emerald-900 block px-1">سعر البيع</label>
              <input 
                type="number" step="0.01"
                className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
                value={formData.price} required
                onChange={e => setFormData({...formData, price: parseFloat(e.target.value) || 0})}
              />
            </div>
            <div className="space-y-1">
              <label className="text-sm font-black text-emerald-900 block px-1">المخزون</label>
              <input 
                type="number"
                className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
                value={formData.stock} required
                onChange={e => setFormData({...formData, stock: parseInt(e.target.value) || 0})}
              />
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900 block px-1">الباركود</label>
            <input 
              type="text" 
              className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
              value={formData.barcode}
              onChange={e => setFormData({...formData, barcode: e.target.value})}
            />
          </div>
          <div className="flex gap-3 pt-6">
            <button type="submit" className="flex-grow bg-emerald-600 text-white py-5 rounded-2xl font-black text-xl shadow-xl active:scale-95 transition-all">
                {initialData ? 'تحديث' : 'إضافة'}
            </button>
            {initialData?.id && (
              <button type="button" onClick={() => onDelete(initialData.id!)} className="bg-red-50 text-red-500 p-5 rounded-2xl active:scale-95 transition-all">
                <Trash2 size={24} />
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Search, Plus, Package, BarChart3, ShoppingCart, X, Save, Trash2, CheckCircle2, History, TrendingUp, AlertCircle, Filter, Calendar, Tag } from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem } from './types';

const formatDate = (date: string) => new Date(date).toLocaleDateString('ar-EG');
const formatTime = (ts: number) => new Date(ts).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' });

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('pos');
  const [accountingSubView, setAccountingSubView] = useState<'sales' | 'inventory'>('sales');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map<number, CartItem>());
  const [isEditOpen, setIsEditOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [checkoutResult, setCheckoutResult] = useState<{status: 'success' | 'error', msg: string} | null>(null);

  // Filters for Inventory Analysis
  const [categoryFilter, setCategoryFilter] = useState<string>('all');
  const [expiryFilter, setExpiryFilter] = useState<'all' | 'soon' | 'expired'>('all');

  const searchInputRef = useRef<HTMLInputElement>(null);

  // Load Data
  const loadData = useCallback(async () => {
    const [allMeds, allSales] = await Promise.all([
      db.medicines.toArray(),
      db.sales.orderBy('timestamp').reverse().toArray()
    ]);
    setMedicines(allMeds);
    setSalesHistory(allSales);
  }, []);

  useEffect(() => {
    loadData();
    if (searchInputRef.current) searchInputRef.current.focus();
  }, [loadData]);

  // POS Actions
  const addToCart = (med: Medicine) => {
    if (med.stock <= 0) {
      setCheckoutResult({status: 'error', msg: 'عذراً، الدواء غير متوفر في المخزون'});
      setTimeout(() => setCheckoutResult(null), 2000);
      return;
    }

    const currentInCart = cart.get(med.id!)?.quantity || 0;
    if (currentInCart >= med.stock) {
        setCheckoutResult({status: 'error', msg: 'الكمية المختارة تتجاوز المخزون'});
        setTimeout(() => setCheckoutResult(null), 2000);
        return;
    }

    const newCart = new Map<number, CartItem>(cart);
    newCart.set(med.id!, { medicine: med, quantity: currentInCart + 1 });
    setCart(newCart);

    if (navigator.vibrate) navigator.vibrate(50);
  };

  const handleCheckout = async () => {
    if (cart.size === 0) return;

    try {
      const items = Array.from(cart.values()) as CartItem[];
      const total = items.reduce((sum, item) => sum + (item.medicine.price * item.quantity), 0);

      await db.transaction('rw', db.medicines, db.sales, async () => {
        for (const item of items) {
          const med = await db.medicines.get(item.medicine.id!);
          if (!med || med.stock < item.quantity) throw new Error(`Stock mismatch for ${item.medicine.name}`);
          await db.medicines.update(item.medicine.id!, { stock: med.stock - item.quantity });
        }

        await db.sales.add({
          totalAmount: total,
          timestamp: Date.now(),
          itemsJson: JSON.stringify(items.map(i => ({ name: i.medicine.name, qty: i.quantity, price: i.medicine.price })))
        });
      });

      setCart(new Map<number, CartItem>());
      setCheckoutResult({status: 'success', msg: `تمت العملية بنجاح! الإجمالي: ${total.toFixed(2)}`});
      loadData();
    } catch (err: any) {
      setCheckoutResult({status: 'error', msg: 'خطأ في العملية: ' + err.message});
    }
    setTimeout(() => setCheckoutResult(null), 3000);
  };

  // Stats Logic
  const todayStats = useMemo(() => {
    const startOfDay = new Date().setHours(0, 0, 0, 0);
    const todaySales = salesHistory.filter(s => s.timestamp >= startOfDay);
    const total = todaySales.reduce((sum, s) => sum + s.totalAmount, 0);
    return { count: todaySales.length, total, history: todaySales };
  }, [salesHistory]);

  const categories = useMemo(() => {
    const cats = new Set(medicines.map(m => m.category || 'عام'));
    return Array.from(cats);
  }, [medicines]);

  // Inventory Analysis Filtering
  const analyzedInventory = useMemo(() => {
    const now = new Date();
    const threeMonthsLater = new Date();
    threeMonthsLater.setMonth(now.getMonth() + 3);

    return medicines.filter(m => {
      const matchesCategory = categoryFilter === 'all' || (m.category || 'عام') === categoryFilter;

      const expDate = new Date(m.expiryDate);
      let matchesExpiry = true;
      if (expiryFilter === 'soon') {
        matchesExpiry = expDate > now && expDate <= threeMonthsLater;
      } else if (expiryFilter === 'expired') {
        matchesExpiry = expDate <= now;
      }

      return matchesCategory && matchesExpiry;
    });
  }, [medicines, categoryFilter, expiryFilter]);

  const filteredMedicines = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return medicines.filter(m => m.name.toLowerCase().includes(q) || m.barcode.toLowerCase().includes(q));
  }, [medicines, searchQuery]);

  // Inventory Logic
  const handleSaveMedicine = async (data: Medicine) => {
    if (data.id) await db.medicines.update(data.id, data);
    else await db.medicines.add(data);
    setIsEditOpen(false);
    setEditingMedicine(null);
    loadData();
  };

  const handleDeleteMedicine = async (id: number) => {
    if (confirm('حذف الدواء نهائياً؟')) {
      await db.medicines.delete(id);
      setIsEditOpen(false);
      loadData();
    }
  };

  const cartTotal = (Array.from(cart.values()) as CartItem[]).reduce((sum, item) => sum + (item.medicine.price * item.quantity), 0);
  const cartItemsCount = (Array.from(cart.values()) as CartItem[]).reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-emerald-50 text-emerald-950 select-none">
      {/* Search Header - Fixed */}
      <header className="bg-emerald-600 p-4 shadow-lg flex-shrink-0 z-20">
        <div className="relative">
          <input
            ref={searchInputRef}
            type="text"
            placeholder="ابحث وبع فوراً (اسم أو باركود)..."
            className="w-full bg-white text-emerald-950 rounded-2xl py-4 px-12 text-lg font-bold shadow-inner focus:ring-4 focus:ring-emerald-300 transition-all border-none"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <Search className="absolute left-4 top-4.5 text-emerald-400" size={24} />
          {searchQuery && (
            <button onClick={() => setSearchQuery('')} className="absolute right-4 top-4.5 text-gray-300">
                <X size={24} />
            </button>
          )}
        </div>
      </header>

      {/* Main View Area */}
      <main className="flex-grow overflow-y-auto dense-list p-2 pb-32">
        {view === 'pos' ? (
          <div className="grid grid-cols-1 gap-2">
            {filteredMedicines.map((med) => (
              <div 
                key={med.id}
                onClick={() => addToCart(med)}
                onContextMenu={(e) => { e.preventDefault(); setEditingMedicine(med); setIsEditOpen(true); }}
                className={`bg-white border-2 ${cart.has(med.id!) ? 'border-emerald-500 bg-emerald-50/50' : 'border-transparent'} p-4 rounded-2xl flex justify-between items-center active:scale-[0.98] transition-all shadow-sm cursor-pointer`}
              >
                <div className="flex-grow">
                  <div className="flex items-center gap-2">
                    <h3 className="font-black text-xl text-emerald-900">{med.name}</h3>
                    {cart.has(med.id!) && (
                        <span className="bg-emerald-600 text-white text-xs px-2 py-0.5 rounded-full font-bold">
                            في السلة: {cart.get(med.id!)?.quantity}
                        </span>
                    )}
                  </div>
                  <div className="flex gap-4 mt-1">
                    <span className="text-xs font-bold text-emerald-600 bg-emerald-100 px-2 py-0.5 rounded-lg">
                        {med.barcode}
                    </span>
                    <span className={`text-xs font-bold ${med.stock < 5 ? 'text-red-500' : 'text-emerald-500'}`}>
                        المخزون: {med.stock}
                    </span>
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-2xl font-black text-emerald-700">{med.price.toFixed(2)}</div>
                  <div className="text-[10px] font-bold text-emerald-400 uppercase">ج.م</div>
                </div>
              </div>
            ))}
            {filteredMedicines.length === 0 && (
                <div className="py-20 text-center opacity-30 flex flex-col items-center">
                    <Package size={80} />
                    <p className="text-xl font-bold mt-4">لا يوجد نتائج</p>
                </div>
            )}
          </div>
        ) : (
          <div className="space-y-4 animate-in fade-in duration-300">
            {/* Accounting Sub-nav */}
            <div className="flex bg-white p-1 rounded-2xl shadow-sm mb-4">
              <button 
                onClick={() => setAccountingSubView('sales')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${accountingSubView === 'sales' ? 'bg-emerald-600 text-white shadow-md' : 'text-emerald-600'}`}
              >
                <History size={18} />
                المبيعات
              </button>
              <button 
                onClick={() => setAccountingSubView('inventory')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${accountingSubView === 'inventory' ? 'bg-emerald-600 text-white shadow-md' : 'text-emerald-600'}`}
              >
                <Filter size={18} />
                تحليل المخزون
              </button>
            </div>

            {accountingSubView === 'sales' ? (
              <>
                <div className="grid grid-cols-2 gap-3">
                   <div className="bg-white p-5 rounded-3xl shadow-sm border-b-4 border-emerald-500">
                      <div className="flex items-center gap-2 text-emerald-600 mb-1">
                        <TrendingUp size={18}/>
                        <span className="font-bold text-sm">مبيعات اليوم</span>
                      </div>
                      <div className="text-3xl font-black text-emerald-900">{todayStats.total.toFixed(2)}</div>
                   </div>
                   <div className="bg-white p-5 rounded-3xl shadow-sm border-b-4 border-emerald-400">
                      <div className="flex items-center gap-2 text-emerald-600 mb-1">
                        <History size={18}/>
                        <span className="font-bold text-sm">عدد الفواتير</span>
                      </div>
                      <div className="text-3xl font-black text-emerald-900">{todayStats.count}</div>
                   </div>
                </div>

                <h3 className="text-xl font-black text-emerald-900 mt-6 flex items-center gap-2">
                    <History className="text-emerald-600" />
                    سجل معاملات اليوم
                </h3>
                <div className="space-y-2">
                    {todayStats.history.map(sale => (
                        <div key={sale.id} className="bg-white p-4 rounded-2xl flex justify-between items-center shadow-sm border-r-4 border-emerald-200">
                            <div>
                                <div className="font-bold text-lg text-emerald-900">{(sale.totalAmount as number).toFixed(2)} ج.م</div>
                                <div className="text-xs text-emerald-500 font-bold">{formatTime(sale.timestamp)}</div>
                            </div>
                            <div className="text-[10px] text-gray-400 max-w-[150px] truncate text-left dir-ltr">
                                {JSON.parse(sale.itemsJson).map((i:any) => i.name).join(', ')}
                            </div>
                        </div>
                    ))}
                    {todayStats.history.length === 0 && (
                         <div className="p-10 text-center text-emerald-300 font-bold border-2 border-dashed border-emerald-100 rounded-3xl">
                            لا توجد مبيعات مسجلة لليوم بعد
                         </div>
                    )}
                </div>
              </>
            ) : (
              <div className="space-y-4">
                {/* Advanced Filtering UI */}
                <div className="bg-white p-4 rounded-3xl shadow-sm space-y-4 border border-emerald-100">
                  <div className="flex items-center gap-2 text-emerald-700 font-bold text-sm mb-2">
                    <Tag size={16} /> التصنيفات
                  </div>
                  <div className="flex flex-wrap gap-2">
                    <button 
                      onClick={() => setCategoryFilter('all')}
                      className={`px-4 py-2 rounded-full text-xs font-bold transition-all ${categoryFilter === 'all' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-emerald-50 text-emerald-600 border border-emerald-100'}`}
                    >
                      الكل
                    </button>
                    {categories.map(cat => (
                      <button 
                        key={cat}
                        onClick={() => setCategoryFilter(cat)}
                        className={`px-4 py-2 rounded-full text-xs font-bold transition-all ${categoryFilter === cat ? 'bg-emerald-600 text-white shadow-lg' : 'bg-emerald-50 text-emerald-600 border border-emerald-100'}`}
                      >
                        {cat}
                      </button>
                    ))}
                  </div>

                  <div className="flex items-center gap-2 text-emerald-700 font-bold text-sm mb-2 mt-4">
                    <Calendar size={16} /> تاريخ الصلاحية
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => setExpiryFilter('all')}
                      className={`flex-1 py-3 rounded-2xl text-xs font-bold transition-all ${expiryFilter === 'all' ? 'bg-emerald-600 text-white' : 'bg-emerald-50 text-emerald-600'}`}
                    >
                      الكل
                    </button>
                    <button 
                      onClick={() => setExpiryFilter('soon')}
                      className={`flex-1 py-3 rounded-2xl text-xs font-bold transition-all ${expiryFilter === 'soon' ? 'bg-orange-500 text-white shadow-orange-200 shadow-lg' : 'bg-orange-50 text-orange-600'}`}
                    >
                      قريباً جداً
                    </button>
                    <button 
                      onClick={() => setExpiryFilter('expired')}
                      className={`flex-1 py-3 rounded-2xl text-xs font-bold transition-all ${expiryFilter === 'expired' ? 'bg-red-500 text-white shadow-red-200 shadow-lg' : 'bg-red-50 text-red-600'}`}
                    >
                      منتهي
                    </button>
                  </div>
                </div>

                <div className="flex justify-between items-center px-2">
                    <h3 className="font-black text-emerald-900">نتائج الفلترة: {analyzedInventory.length} دواء</h3>
                </div>

                <div className="space-y-2">
                  {analyzedInventory.map(med => {
                    const isExpired = new Date(med.expiryDate) <= new Date();
                    const isSoon = !isExpired && new Date(med.expiryDate) <= new Date(Date.now() + 90 * 24 * 60 * 60 * 1000);

                    return (
                      <div 
                        key={med.id} 
                        onClick={() => { setEditingMedicine(med); setIsEditOpen(true); }}
                        className="bg-white p-4 rounded-2xl flex justify-between items-center shadow-sm border-r-8 border-emerald-500"
                        style={{ borderRightColor: isExpired ? '#ef4444' : isSoon ? '#f97316' : '#10b981' }}
                      >
                        <div>
                          <div className="font-bold text-emerald-900">{med.name}</div>
                          <div className="text-[10px] text-emerald-500 flex gap-2">
                            <span>{med.category || 'عام'}</span>
                            <span className={isExpired ? 'text-red-600 font-black' : isSoon ? 'text-orange-600 font-black' : ''}>
                              تنتهي: {formatDate(med.expiryDate)}
                            </span>
                          </div>
                        </div>
                        <div className="text-right">
                          <div className={`font-black ${med.stock < 5 ? 'text-red-500' : 'text-emerald-700'}`}>
                            {med.stock} <span className="text-[10px] font-normal opacity-50">في المخزن</span>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                  {analyzedInventory.length === 0 && (
                     <div className="p-10 text-center text-emerald-300 font-bold border-2 border-dashed border-emerald-100 rounded-3xl">
                        لا توجد أدوية مطابقة للفلتر المحدد
                     </div>
                  )}
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {/* Floating Status Notification */}
      {checkoutResult && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-50 px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top duration-300 font-bold text-lg
            ${checkoutResult.status === 'success' ? 'bg-emerald-600 text-white' : 'bg-red-500 text-white'}`}>
          {checkoutResult.status === 'success' ? <CheckCircle2 /> : <AlertCircle />}
          {checkoutResult.msg}
        </div>
      )}

      {/* Persistent Cart Bar (Only in POS) */}
      {view === 'pos' && cart.size > 0 && (
        <div className="fixed bottom-20 left-0 right-0 p-4 z-30 pointer-events-none">
            <div className="max-w-md mx-auto bg-emerald-900/95 backdrop-blur-md text-white p-4 rounded-3xl flex items-center justify-between shadow-2xl shadow-emerald-900/40 pointer-events-auto border border-emerald-500/30">
                <div className="flex items-center gap-4">
                    <div className="relative">
                        <ShoppingCart size={32} />
                        <span className="absolute -top-2 -right-2 bg-red-500 text-white text-[10px] font-black h-5 w-5 rounded-full flex items-center justify-center border-2 border-emerald-900">
                            {cartItemsCount}
                        </span>
                    </div>
                    <div>
                        <div className="text-2xl font-black">{cartTotal.toFixed(2)} <span className="text-xs font-normal opacity-70">ج.م</span></div>
                        <div className="text-[10px] opacity-50 font-bold">إجمالي السلة</div>
                    </div>
                </div>
                <button 
                    onClick={handleCheckout}
                    className="bg-emerald-500 hover:bg-emerald-400 text-white px-8 py-3 rounded-2xl font-black text-lg active:scale-95 transition-all shadow-lg"
                >
                    تأكيد البيع
                </button>
            </div>
        </div>
      )}

      {/* Bottom Nav */}
      <nav className="bg-white border-t border-emerald-100 flex justify-around p-3 pb-8 flex-shrink-0 z-40">
        <button onClick={() => setView('pos')} className={`flex flex-col items-center gap-1 transition-all ${view === 'pos' ? 'text-emerald-600 scale-110' : 'text-gray-400'}`}>
          <Package size={26} strokeWidth={view === 'pos' ? 3 : 2} />
          <span className="text-[10px] font-black">الكاشير</span>
        </button>
        <div className="relative -mt-10">
            <button 
                onClick={() => { setEditingMedicine(null); setIsEditOpen(true); }}
                className="bg-emerald-500 text-white p-5 rounded-full shadow-xl shadow-emerald-200 active:scale-90 transition-transform"
            >
                <Plus size={32} strokeWidth={3} />
            </button>
        </div>
        <button onClick={() => setView('accounting')} className={`flex flex-col items-center gap-1 transition-all ${view === 'accounting' ? 'text-emerald-600 scale-110' : 'text-gray-400'}`}>
          <BarChart3 size={26} strokeWidth={view === 'accounting' ? 3 : 2} />
          <span className="text-[10px] font-black">الحسابات</span>
        </button>
      </nav>

      {/* Modal Layer */}
      {isEditOpen && (
        <MedicineDialog 
          categories={categories}
          initialData={editingMedicine} 
          onSave={handleSaveMedicine} 
          onClose={() => setIsEditOpen(false)}
          onDelete={handleDeleteMedicine}
        />
      )}
    </div>
  );
};

const MedicineDialog: React.FC<{
  initialData: Medicine | null;
  categories: string[];
  onSave: (data: Medicine) => void;
  onClose: () => void;
  onDelete: (id: number) => void;
}> = ({ initialData, categories, onSave, onClose, onDelete }) => {
  const [formData, setFormData] = useState<Medicine>(
    initialData || { name: '', barcode: '', price: 0, stock: 0, category: 'عام', expiryDate: new Date().toISOString().split('T')[0] }
  );

  const nameRef = useRef<HTMLInputElement>(null);
  useEffect(() => { if (nameRef.current) nameRef.current.focus(); }, []);

  return (
    <div className="fixed inset-0 bg-emerald-950/40 backdrop-blur-md z-[100] flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-[40px] overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto">
        <div className="sticky top-0 bg-emerald-600 p-6 text-white flex justify-between items-center z-10">
          <h2 className="text-2xl font-black">{initialData ? 'تعديل المخزون' : 'إضافة دواء'}</h2>
          <button onClick={onClose} className="p-2 bg-emerald-700/50 rounded-full"><X size={24}/></button>
        </div>
        <form onSubmit={(e) => { e.preventDefault(); onSave(formData); }} className="p-8 space-y-5">
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900 block px-1">الاسم التجاري</label>
            <input 
              ref={nameRef}
              type="text" 
              className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 focus:bg-white transition-all outline-none"
              value={formData.name}
              required
              onChange={e => setFormData({...formData, name: e.target.value})}
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-sm font-black text-emerald-900 block px-1">سعر البيع</label>
              <input 
                type="number" step="0.01"
                className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
                value={formData.price} required
                onChange={e => setFormData({...formData, price: parseFloat(e.target.value) || 0})}
              />
            </div>
            <div className="space-y-1">
              <label className="text-sm font-black text-emerald-900 block px-1">المخزون</label>
              <input 
                type="number"
                className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
                value={formData.stock} required
                onChange={e => setFormData({...formData, stock: parseInt(e.target.value) || 0})}
              />
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900 block px-1">التصنيف</label>
            <div className="relative">
              <input 
                type="text" 
                list="category-list"
                className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
                value={formData.category}
                onChange={e => setFormData({...formData, category: e.target.value})}
              />
              <datalist id="category-list">
                {categories.map(c => <option key={c} value={c} />)}
              </datalist>
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900 block px-1">الباركود</label>
            <input 
              type="text" 
              className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
              value={formData.barcode}
              onChange={e => setFormData({...formData, barcode: e.target.value})}
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900 block px-1">تاريخ انتهاء الصلاحية</label>
            <input 
              type="date" 
              className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
              value={formData.expiryDate}
              required
              onChange={e => setFormData({...formData, expiryDate: e.target.value})}
            />
          </div>
          <div className="flex gap-3 pt-6">
            <button type="submit" className="flex-grow bg-emerald-600 text-white py-5 rounded-2xl font-black text-xl shadow-xl active:scale-95 transition-all">
                {initialData ? 'تحديث' : 'إضافة'}
            </button>
            {initialData?.id && (
              <button type="button" onClick={() => onDelete(initialData.id!)} className="bg-red-50 text-red-500 p-5 rounded-2xl active:scale-95 transition-all">
                <Trash2 size={24} />
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default App;

import { Dexie, Table } from 'dexie';
import { Medicine, Sale } from './types';

// Extend Dexie to create our PharmacyDB class with strictly typed tables
export class PharmacyDB extends Dexie {
  medicines!: Table<Medicine>;
  sales!: Table<Sale>;

  constructor() {
    super('PharmacyDB');
    // Configure database schema version and store definitions
    // Use named import to ensure the base class methods like 'version' and 'transaction' are properly inherited
    this.version(1).stores({
      medicines: '++id, name, barcode, stock, expiryDate',
      sales: '++id, timestamp'
    });
  }
}

export const db = new PharmacyDB();

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Search, Plus, Package, BarChart3, ShoppingCart, X, Save, Trash2, CheckCircle2, History, TrendingUp, AlertCircle, Filter, Calendar, Tag } from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem } from './types';

const formatDate = (date: string) => new Date(date).toLocaleDateString('ar-EG');
const formatTime = (ts: number) => new Date(ts).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' });

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('pos');
  const [accountingSubView, setAccountingSubView] = useState<'sales' | 'inventory'>('sales');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map<number, CartItem>());
  const [isEditOpen, setIsEditOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [checkoutResult, setCheckoutResult] = useState<{status: 'success' | 'error', msg: string} | null>(null);

  // Filters for Inventory Analysis
  const [categoryFilter, setCategoryFilter] = useState<string>('all');
  const [expiryFilter, setExpiryFilter] = useState<'all' | 'soon' | 'expired'>('all');

  const searchInputRef = useRef<HTMLInputElement>(null);

  // Load Data
  const loadData = useCallback(async () => {
    const [allMeds, allSales] = await Promise.all([
      db.medicines.toArray(),
      db.sales.orderBy('timestamp').reverse().toArray()
    ]);
    setMedicines(allMeds);
    setSalesHistory(allSales);
  }, []);

  useEffect(() => {
    loadData();
    if (searchInputRef.current) searchInputRef.current.focus();
  }, [loadData]);

  // POS Actions
  const addToCart = (med: Medicine) => {
    if (med.id === undefined) return;

    if (med.stock <= 0) {
      setCheckoutResult({status: 'error', msg: 'عذراً، الدواء غير متوفر في المخزون'});
      setTimeout(() => setCheckoutResult(null), 2000);
      return;
    }

    const currentInCart = cart.get(med.id)?.quantity || 0;
    if (currentInCart >= med.stock) {
        setCheckoutResult({status: 'error', msg: 'الكمية المختارة تتجاوز المخزون'});
        setTimeout(() => setCheckoutResult(null), 2000);
        return;
    }

    const newCart = new Map<number, CartItem>(cart);
    newCart.set(med.id, { medicine: med, quantity: currentInCart + 1 });
    setCart(newCart);

    if (navigator.vibrate) navigator.vibrate(50);
  };

  const handleCheckout = async () => {
    if (cart.size === 0) return;

    try {
      const items = Array.from(cart.values()) as CartItem[];
      const total = items.reduce((sum, item) => sum + (item.medicine.price * item.quantity), 0);

      // Fixed transaction call by ensuring correct inheritance in db.ts and using standard table array signature
      await db.transaction('rw', [db.medicines, db.sales], async () => {
        for (const item of items) {
          const med = await db.medicines.get(item.medicine.id!);
          if (!med || med.stock < item.quantity) throw new Error(`Stock mismatch for ${item.medicine.name}`);
          await db.medicines.update(item.medicine.id!, { stock: med.stock - item.quantity });
        }

        await db.sales.add({
          totalAmount: total,
          timestamp: Date.now(),
          itemsJson: JSON.stringify(items.map(i => ({ name: i.medicine.name, qty: i.quantity, price: i.medicine.price })))
        });
      });

      setCart(new Map<number, CartItem>());
      setCheckoutResult({status: 'success', msg: `تمت العملية بنجاح! الإجمالي: ${total.toFixed(2)}`});
      loadData();
    } catch (err: any) {
      setCheckoutResult({status: 'error', msg: 'خطأ في العملية: ' + err.message});
    }
    setTimeout(() => setCheckoutResult(null), 3000);
  };

  // Stats Logic
  const todayStats = useMemo(() => {
    const startOfDay = new Date().setHours(0, 0, 0, 0);
    const todaySales = salesHistory.filter(s => s.timestamp >= startOfDay);
    const total = todaySales.reduce((sum, s) => sum + s.totalAmount, 0);
    return { count: todaySales.length, total, history: todaySales };
  }, [salesHistory]);

  const categories = useMemo(() => {
    const cats = new Set(medicines.map(m => m.category || 'عام'));
    return Array.from(cats);
  }, [medicines]);

  // Inventory Analysis Filtering
  const analyzedInventory = useMemo(() => {
    const now = new Date();
    const threeMonthsLater = new Date();
    threeMonthsLater.setMonth(now.getMonth() + 3);

    return medicines.filter(m => {
      const matchesCategory = categoryFilter === 'all' || (m.category || 'عام') === categoryFilter;

      const expDate = new Date(m.expiryDate);
      let matchesExpiry = true;
      if (expiryFilter === 'soon') {
        matchesExpiry = expDate > now && expDate <= threeMonthsLater;
      } else if (expiryFilter === 'expired') {
        matchesExpiry = expDate <= now;
      }

      return matchesCategory && matchesExpiry;
    });
  }, [medicines, categoryFilter, expiryFilter]);

  const filteredMedicines = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return medicines.filter(m => m.name.toLowerCase().includes(q) || m.barcode.toLowerCase().includes(q));
  }, [medicines, searchQuery]);

  // Inventory Logic
  const handleSaveMedicine = async (data: Medicine) => {
    if (data.id) await db.medicines.update(data.id, data);
    else await db.medicines.add(data);
    setIsEditOpen(false);
    setEditingMedicine(null);
    loadData();
  };

  const handleDeleteMedicine = async (id: number) => {
    if (confirm('حذف الدواء نهائياً؟')) {
      await db.medicines.delete(id);
      setIsEditOpen(false);
      loadData();
    }
  };

  const cartTotal = (Array.from(cart.values()) as CartItem[]).reduce((sum, item) => sum + (item.medicine.price * item.quantity), 0);
  const cartItemsCount = (Array.from(cart.values()) as CartItem[]).reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-emerald-50 text-emerald-950 select-none">
      {/* Search Header - Fixed */}
      <header className="bg-emerald-600 p-4 shadow-lg flex-shrink-0 z-20">
        <div className="relative">
          <input
            ref={searchInputRef}
            type="text"
            placeholder="ابحث وبع فوراً (اسم أو باركود)..."
            className="w-full bg-white text-emerald-950 rounded-2xl py-4 px-12 text-lg font-bold shadow-inner focus:ring-4 focus:ring-emerald-300 transition-all border-none"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <Search className="absolute left-4 top-4.5 text-emerald-400" size={24} />
          {searchQuery && (
            <button onClick={() => setSearchQuery('')} className="absolute right-4 top-4.5 text-gray-300">
                <X size={24} />
            </button>
          )}
        </div>
      </header>

      {/* Main View Area */}
      <main className="flex-grow overflow-y-auto dense-list p-2 pb-32">
        {view === 'pos' ? (
          <div className="grid grid-cols-1 gap-2">
            {filteredMedicines.map((med) => (
              <div 
                key={med.id}
                onClick={() => addToCart(med)}
                onContextMenu={(e) => { e.preventDefault(); setEditingMedicine(med); setIsEditOpen(true); }}
                className={`bg-white border-2 ${cart.has(med.id!) ? 'border-emerald-500 bg-emerald-50/50' : 'border-transparent'} p-4 rounded-2xl flex justify-between items-center active:scale-[0.98] transition-all shadow-sm cursor-pointer`}
              >
                <div className="flex-grow">
                  <div className="flex items-center gap-2">
                    <h3 className="font-black text-xl text-emerald-900">{med.name}</h3>
                    {cart.has(med.id!) && (
                        <span className="bg-emerald-600 text-white text-xs px-2 py-0.5 rounded-full font-bold">
                            في السلة: {cart.get(med.id!)?.quantity}
                        </span>
                    )}
                  </div>
                  <div className="flex gap-4 mt-1">
                    <span className="text-xs font-bold text-emerald-600 bg-emerald-100 px-2 py-0.5 rounded-lg">
                        {med.barcode}
                    </span>
                    <span className={`text-xs font-bold ${med.stock < 5 ? 'text-red-500' : 'text-emerald-500'}`}>
                        المخزون: {med.stock}
                    </span>
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-2xl font-black text-emerald-700">{med.price.toFixed(2)}</div>
                  <div className="text-[10px] font-bold text-emerald-400 uppercase">ج.م</div>
                </div>
              </div>
            ))}
            {filteredMedicines.length === 0 && (
                <div className="py-20 text-center opacity-30 flex flex-col items-center">
                    <Package size={80} />
                    <p className="text-xl font-bold mt-4">لا يوجد نتائج</p>
                </div>
            )}
          </div>
        ) : (
          <div className="space-y-4 animate-in fade-in duration-300">
            {/* Accounting Sub-nav */}
            <div className="flex bg-white p-1 rounded-2xl shadow-sm mb-4">
              <button 
                onClick={() => setAccountingSubView('sales')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${accountingSubView === 'sales' ? 'bg-emerald-600 text-white shadow-md' : 'text-emerald-600'}`}
              >
                <History size={18} />
                المبيعات
              </button>
              <button 
                onClick={() => setAccountingSubView('inventory')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${accountingSubView === 'inventory' ? 'bg-emerald-600 text-white shadow-md' : 'text-emerald-600'}`}
              >
                <Filter size={18} />
                تحليل المخزون
              </button>
            </div>

            {accountingSubView === 'sales' ? (
              <>
                <div className="grid grid-cols-2 gap-3">
                   <div className="bg-white p-5 rounded-3xl shadow-sm border-b-4 border-emerald-500">
                      <div className="flex items-center gap-2 text-emerald-600 mb-1">
                        <TrendingUp size={18}/>
                        <span className="font-bold text-sm">مبيعات اليوم</span>
                      </div>
                      <div className="text-3xl font-black text-emerald-900">{todayStats.total.toFixed(2)}</div>
                   </div>
                   <div className="bg-white p-5 rounded-3xl shadow-sm border-b-4 border-emerald-400">
                      <div className="flex items-center gap-2 text-emerald-600 mb-1">
                        <History size={18}/>
                        <span className="font-bold text-sm">عدد الفواتير</span>
                      </div>
                      <div className="text-3xl font-black text-emerald-900">{todayStats.count}</div>
                   </div>
                </div>

                <h3 className="text-xl font-black text-emerald-900 mt-6 flex items-center gap-2">
                    <History className="text-emerald-600" />
                    سجل معاملات اليوم
                </h3>
                <div className="space-y-2">
                    {todayStats.history.map(sale => (
                        <div key={sale.id} className="bg-white p-4 rounded-2xl flex justify-between items-center shadow-sm border-r-4 border-emerald-200">
                            <div>
                                <div className="font-bold text-lg text-emerald-900">{(sale.totalAmount as number).toFixed(2)} ج.م</div>
                                <div className="text-xs text-emerald-500 font-bold">{formatTime(sale.timestamp)}</div>
                            </div>
                            <div className="text-[10px] text-gray-400 max-w-[150px] truncate text-left dir-ltr">
                                {JSON.parse(sale.itemsJson).map((i:any) => i.name).join(', ')}
                            </div>
                        </div>
                    ))}
                    {todayStats.history.length === 0 && (
                         <div className="p-10 text-center text-emerald-300 font-bold border-2 border-dashed border-emerald-100 rounded-3xl">
                            لا توجد مبيعات مسجلة لليوم بعد
                         </div>
                    )}
                </div>
              </>
            ) : (
              <div className="space-y-4">
                {/* Advanced Filtering UI */}
                <div className="bg-white p-4 rounded-3xl shadow-sm space-y-4 border border-emerald-100">
                  <div className="flex items-center gap-2 text-emerald-700 font-bold text-sm mb-2">
                    <Tag size={16} /> التصنيفات
                  </div>
                  <div className="flex flex-wrap gap-2">
                    <button 
                      onClick={() => setCategoryFilter('all')}
                      className={`px-4 py-2 rounded-full text-xs font-bold transition-all ${categoryFilter === 'all' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-emerald-50 text-emerald-600 border border-emerald-100'}`}
                    >
                      الكل
                    </button>
                    {categories.map(cat => (
                      <button 
                        key={cat}
                        onClick={() => setCategoryFilter(cat)}
                        className={`px-4 py-2 rounded-full text-xs font-bold transition-all ${categoryFilter === cat ? 'bg-emerald-600 text-white shadow-lg' : 'bg-emerald-50 text-emerald-600 border border-emerald-100'}`}
                      >
                        {cat}
                      </button>
                    ))}
                  </div>

                  <div className="flex items-center gap-2 text-emerald-700 font-bold text-sm mb-2 mt-4">
                    <Calendar size={16} /> تاريخ الصلاحية
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => setExpiryFilter('all')}
                      className={`flex-1 py-3 rounded-2xl text-xs font-bold transition-all ${expiryFilter === 'all' ? 'bg-emerald-600 text-white' : 'bg-emerald-50 text-emerald-600'}`}
                    >
                      الكل
                    </button>
                    <button 
                      onClick={() => setExpiryFilter('soon')}
                      className={`flex-1 py-3 rounded-2xl text-xs font-bold transition-all ${expiryFilter === 'soon' ? 'bg-orange-500 text-white shadow-orange-200 shadow-lg' : 'bg-orange-50 text-orange-600'}`}
                    >
                      قريباً جداً
                    </button>
                    <button 
                      onClick={() => setExpiryFilter('expired')}
                      className={`flex-1 py-3 rounded-2xl text-xs font-bold transition-all ${expiryFilter === 'expired' ? 'bg-red-500 text-white shadow-red-200 shadow-lg' : 'bg-red-50 text-red-600'}`}
                    >
                      منتهي
                    </button>
                  </div>
                </div>

                <div className="flex justify-between items-center px-2">
                    <h3 className="font-black text-emerald-900">نتائج الفلترة: {analyzedInventory.length} دواء</h3>
                </div>

                <div className="space-y-2">
                  {analyzedInventory.map(med => {
                    const isExpired = new Date(med.expiryDate) <= new Date();
                    const isSoon = !isExpired && new Date(med.expiryDate) <= new Date(Date.now() + 90 * 24 * 60 * 60 * 1000);

                    return (
                      <div 
                        key={med.id} 
                        onClick={() => { setEditingMedicine(med); setIsEditOpen(true); }}
                        className="bg-white p-4 rounded-2xl flex justify-between items-center shadow-sm border-r-8 border-emerald-500"
                        style={{ borderRightColor: isExpired ? '#ef4444' : isSoon ? '#f97316' : '#10b981' }}
                      >
                        <div>
                          <div className="font-bold text-emerald-900">{med.name}</div>
                          <div className="text-[10px] text-emerald-500 flex gap-2">
                            <span>{med.category || 'عام'}</span>
                            <span className={isExpired ? 'text-red-600 font-black' : isSoon ? 'text-orange-600 font-black' : ''}>
                              تنتهي: {formatDate(med.expiryDate)}
                            </span>
                          </div>
                        </div>
                        <div className="text-right">
                          <div className={`font-black ${med.stock < 5 ? 'text-red-500' : 'text-emerald-700'}`}>
                            {med.stock} <span className="text-[10px] font-normal opacity-50">في المخزن</span>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                  {analyzedInventory.length === 0 && (
                     <div className="p-10 text-center text-emerald-300 font-bold border-2 border-dashed border-emerald-100 rounded-3xl">
                        لا توجد أدوية مطابقة للفلتر المحدد
                     </div>
                  )}
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {/* Floating Status Notification */}
      {checkoutResult && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-50 px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top duration-300 font-bold text-lg
            ${checkoutResult.status === 'success' ? 'bg-emerald-600 text-white' : 'bg-red-500 text-white'}`}>
          {checkoutResult.status === 'success' ? <CheckCircle2 /> : <AlertCircle />}
          {checkoutResult.msg}
        </div>
      )}

      {/* Persistent Cart Bar (Only in POS) */}
      {view === 'pos' && cart.size > 0 && (
        <div className="fixed bottom-20 left-0 right-0 p-4 z-30 pointer-events-none">
            <div className="max-w-md mx-auto bg-emerald-900/95 backdrop-blur-md text-white p-4 rounded-3xl flex items-center justify-between shadow-2xl shadow-emerald-900/40 pointer-events-auto border border-emerald-500/30">
                <div className="flex items-center gap-4">
                    <div className="relative">
                        <ShoppingCart size={32} />
                        <span className="absolute -top-2 -right-2 bg-red-500 text-white text-[10px] font-black h-5 w-5 rounded-full flex items-center justify-center border-2 border-emerald-900">
                            {cartItemsCount}
                        </span>
                    </div>
                    <div>
                        <div className="text-2xl font-black">{cartTotal.toFixed(2)} <span className="text-xs font-normal opacity-70">ج.م</span></div>
                        <div className="text-[10px] opacity-50 font-bold">إجمالي السلة</div>
                    </div>
                </div>
                <button 
                    onClick={handleCheckout}
                    className="bg-emerald-500 hover:bg-emerald-400 text-white px-8 py-3 rounded-2xl font-black text-lg active:scale-95 transition-all shadow-lg"
                >
                    تأكيد البيع
                </button>
            </div>
        </div>
      )}

      {/* Bottom Nav */}
      <nav className="bg-white border-t border-emerald-100 flex justify-around p-3 pb-8 flex-shrink-0 z-40">
        <button onClick={() => setView('pos')} className={`flex flex-col items-center gap-1 transition-all ${view === 'pos' ? 'text-emerald-600 scale-110' : 'text-gray-400'}`}>
          <Package size={26} strokeWidth={view === 'pos' ? 3 : 2} />
          <span className="text-[10px] font-black">الكاشير</span>
        </button>
        <div className="relative -mt-10">
            <button 
                onClick={() => { setEditingMedicine(null); setIsEditOpen(true); }}
                className="bg-emerald-500 text-white p-5 rounded-full shadow-xl shadow-emerald-200 active:scale-90 transition-transform"
            >
                <Plus size={32} strokeWidth={3} />
            </button>
        </div>
        <button onClick={() => setView('accounting')} className={`flex flex-col items-center gap-1 transition-all ${view === 'accounting' ? 'text-emerald-600 scale-110' : 'text-gray-400'}`}>
          <BarChart3 size={26} strokeWidth={view === 'accounting' ? 3 : 2} />
          <span className="text-[10px] font-black">الحسابات</span>
        </button>
      </nav>

      {/* Modal Layer */}
      {isEditOpen && (
        <MedicineDialog 
          categories={categories}
          initialData={editingMedicine} 
          onSave={handleSaveMedicine} 
          onClose={() => setIsEditOpen(false)}
          onDelete={handleDeleteMedicine}
        />
      )}
    </div>
  );
};

const MedicineDialog: React.FC<{
  initialData: Medicine | null;
  categories: string[];
  onSave: (data: Medicine) => void;
  onClose: () => void;
  onDelete: (id: number) => void;
}> = ({ initialData, categories, onSave, onClose, onDelete }) => {
  const [formData, setFormData] = useState<Medicine>(
    initialData || { name: '', barcode: '', price: 0, stock: 0, category: 'عام', expiryDate: new Date().toISOString().split('T')[0] }
  );

  const nameRef = useRef<HTMLInputElement>(null);
  useEffect(() => { if (nameRef.current) nameRef.current.focus(); }, []);

  return (
    <div className="fixed inset-0 bg-emerald-950/40 backdrop-blur-md z-[100] flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-[40px] overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto">
        <div className="sticky top-0 bg-emerald-600 p-6 text-white flex justify-between items-center z-10">
          <h2 className="text-2xl font-black">{initialData ? 'تعديل المخزون' : 'إضافة دواء'}</h2>
          <button onClick={onClose} className="p-2 bg-emerald-700/50 rounded-full"><X size={24}/></button>
        </div>
        <form onSubmit={(e) => { e.preventDefault(); onSave(formData); }} className="p-8 space-y-5">
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900 block px-1">الاسم التجاري</label>
            <input 
              ref={nameRef}
              type="text" 
              className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 focus:bg-white transition-all outline-none"
              value={formData.name}
              required
              onChange={e => setFormData({...formData, name: e.target.value})}
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-sm font-black text-emerald-900 block px-1">سعر البيع</label>
              <input 
                type="number" step="0.01"
                className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
                value={formData.price} required
                onChange={e => setFormData({...formData, price: parseFloat(e.target.value) || 0})}
              />
            </div>
            <div className="space-y-1">
              <label className="text-sm font-black text-emerald-900 block px-1">المخزون</label>
              <input 
                type="number"
                className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
                value={formData.stock} required
                onChange={e => setFormData({...formData, stock: parseInt(e.target.value) || 0})}
              />
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900 block px-1">التصنيف</label>
            <div className="relative">
              <input 
                type="text" 
                list="category-list"
                className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
                value={formData.category}
                onChange={e => setFormData({...formData, category: e.target.value})}
              />
              <datalist id="category-list">
                {categories.map(c => <option key={c} value={c} />)}
              </datalist>
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900 block px-1">الباركود</label>
            <input 
              type="text" 
              className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
              value={formData.barcode}
              onChange={e => setFormData({...formData, barcode: e.target.value})}
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900 block px-1">تاريخ انتهاء الصلاحية</label>
            <input 
              type="date" 
              className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 transition-all outline-none"
              value={formData.expiryDate}
              required
              onChange={e => setFormData({...formData, expiryDate: e.target.value})}
            />
          </div>
          <div className="flex gap-3 pt-6">
            <button type="submit" className="flex-grow bg-emerald-600 text-white py-5 rounded-2xl font-black text-xl shadow-xl active:scale-95 transition-all">
                {initialData ? 'تحديث' : 'إضافة'}
            </button>
            {initialData?.id && (
              <button type="button" onClick={() => onDelete(initialData.id!)} className="bg-red-50 text-red-500 p-5 rounded-2xl active:scale-95 transition-all">
                <Trash2 size={24} />
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default App;

export interface Medicine {
  id?: number;
  name: string;
  barcode: string;
  price: number;
  costPrice: number; // For profit calculations
  stock: number;
  category: string;
  expiryDate: string;
}

export interface Sale {
  id?: number;
  totalAmount: number;
  totalCost: number; // To track profit
  timestamp: number;
  itemsJson: string; // List of {name, price, costPrice, quantity}
}

export interface CartItem {
  medicine: Medicine;
  quantity: number;
}

export type ViewType = 'pos' | 'accounting';

import { Dexie, Table } from 'dexie';
import { Medicine, Sale } from './types';

export class PharmacyDB extends Dexie {
  medicines!: Table<Medicine>;
  sales!: Table<Sale>;

  constructor() {
    super('PharmacyDB');
    this.version(2).stores({
      // Added indices for name and barcode to ensure O(1) or O(log n) search speed
      medicines: '++id, *name, *barcode, stock, expiryDate, category',
      sales: '++id, timestamp'
    });
  }
}

export const db = new PharmacyDB();

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Search, Plus, Package, BarChart3, ShoppingCart, X, Save, Trash2, CheckCircle2, History, TrendingUp, AlertCircle, Filter, Calendar, Tag, Coins } from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem } from './types';

const formatDate = (date: string) => new Date(date).toLocaleDateString('ar-EG');
const formatTime = (ts: number) => new Date(ts).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' });

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('pos');
  const [accountingSubView, setAccountingSubView] = useState<'sales' | 'inventory'>('sales');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map<number, CartItem>());
  const [isEditOpen, setIsEditOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [checkoutResult, setCheckoutResult] = useState<{status: 'success' | 'error', msg: string} | null>(null);

  const [categoryFilter, setCategoryFilter] = useState<string>('all');
  const [expiryFilter, setExpiryFilter] = useState<'all' | 'soon' | 'expired'>('all');

  const searchInputRef = useRef<HTMLInputElement>(null);

  const loadData = useCallback(async () => {
    // Optimization: Order medicines by ID descending to show newest first
    const [allMeds, allSales] = await Promise.all([
      db.medicines.reverse().toArray(),
      db.sales.orderBy('timestamp').reverse().toArray()
    ]);
    setMedicines(allMeds);
    setSalesHistory(allSales);
  }, []);

  useEffect(() => {
    loadData();
    if (searchInputRef.current) searchInputRef.current.focus();
  }, [loadData]);

  const addToCart = (med: Medicine) => {
    if (med.id === undefined) return;

    // Safety check: Stock 0
    if (med.stock <= 0) {
      setCheckoutResult({status: 'error', msg: 'عذراً، هذا الصنف نفذ من المخزن'});
      setTimeout(() => setCheckoutResult(null), 2000);
      return;
    }

    const newCart = new Map<number, CartItem>(cart);
    const existing = newCart.get(med.id);
    const currentQty = existing?.quantity || 0;

    // Safety check: Exceeding stock
    if (currentQty >= med.stock) {
        setCheckoutResult({status: 'error', msg: 'الكمية المختارة تتجاوز المتاح في المخزن'});
        setTimeout(() => setCheckoutResult(null), 2000);
        return;
    }

    // Logical Improvement: Merge duplicates instead of adding new lines
    newCart.set(med.id, { medicine: med, quantity: currentQty + 1 });
    setCart(newCart);

    if (navigator.vibrate) navigator.vibrate(40);
  };

  const clearCart = () => {
    if (confirm('هل تريد مسح جميع محتويات السلة؟')) {
      setCart(new Map());
    }
  };

  const handleCheckout = async () => {
    if (cart.size === 0) return;

    try {
      const items = Array.from(cart.values());
      const totalAmount = items.reduce((sum, item) => sum + (item.medicine.price * item.quantity), 0);
      const totalCost = items.reduce((sum, item) => sum + (item.medicine.costPrice * item.quantity), 0);

      // ATOMIC TRANSACTION: Ensuring stock update and sale logging are inseparable
      await db.transaction('rw', [db.medicines, db.sales], async () => {
        for (const item of items) {
          const currentMed = await db.medicines.get(item.medicine.id!);
          if (!currentMed || currentMed.stock < item.quantity) {
            throw new Error(`نقص مفاجئ في مخزون ${item.medicine.name}`);
          }
          await db.medicines.update(item.medicine.id!, { 
            stock: currentMed.stock - item.quantity 
          });
        }

        await db.sales.add({
          totalAmount,
          totalCost,
          timestamp: Date.now(),
          itemsJson: JSON.stringify(items.map(i => ({ 
            name: i.medicine.name, 
            qty: i.quantity, 
            price: i.medicine.price,
            cost: i.medicine.costPrice
          })))
        });
      });

      setCart(new Map());
      setCheckoutResult({status: 'success', msg: `تمت عملية البيع! الإجمالي: ${totalAmount.toFixed(2)}`});
      loadData();
    } catch (err: any) {
      setCheckoutResult({status: 'error', msg: err.message || 'خطأ غير متوقع'});
    }
    setTimeout(() => setCheckoutResult(null), 3000);
  };

  const todayStats = useMemo(() => {
    const startOfDay = new Date().setHours(0, 0, 0, 0);
    const todaySales = salesHistory.filter(s => s.timestamp >= startOfDay);
    const revenue = todaySales.reduce((sum, s) => sum + s.totalAmount, 0);
    const cost = todaySales.reduce((sum, s) => sum + (s.totalCost || 0), 0);
    return { count: todaySales.length, revenue, profit: revenue - cost, history: todaySales };
  }, [salesHistory]);

  const categories = useMemo(() => {
    const cats = new Set(medicines.map(m => m.category || 'عام'));
    return Array.from(cats);
  }, [medicines]);

  const filteredMedicines = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    // High-speed filtering on in-memory array (suitable for <5000 items)
    return medicines.filter(m => 
      m.name.toLowerCase().includes(q) || 
      m.barcode.toLowerCase().includes(q)
    );
  }, [medicines, searchQuery]);

  const analyzedInventory = useMemo(() => {
    const now = new Date();
    const threeMonthsLater = new Date();
    threeMonthsLater.setMonth(now.getMonth() + 3);

    return medicines.filter(m => {
      const matchesCategory = categoryFilter === 'all' || (m.category || 'عام') === categoryFilter;
      const expDate = new Date(m.expiryDate);
      let matchesExpiry = true;
      if (expiryFilter === 'soon') matchesExpiry = expDate > now && expDate <= threeMonthsLater;
      else if (expiryFilter === 'expired') matchesExpiry = expDate <= now;
      return matchesCategory && matchesExpiry;
    });
  }, [medicines, categoryFilter, expiryFilter]);

  const handleSaveMedicine = async (data: Medicine) => {
    if (data.id) await db.medicines.update(data.id, data);
    else await db.medicines.add(data);
    setIsEditOpen(false);
    setEditingMedicine(null);
    loadData();
  };

  const handleDeleteMedicine = async (id: number) => {
    if (confirm('حذف الدواء نهائياً من النظام؟')) {
      await db.medicines.delete(id);
      setIsEditOpen(false);
      loadData();
    }
  };

  const cartTotal = Array.from(cart.values()).reduce((sum, item) => sum + (item.medicine.price * item.quantity), 0);
  const cartItemsCount = Array.from(cart.values()).reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-emerald-50 text-emerald-950 select-none">
      {/* Dynamic Header */}
      <header className="bg-emerald-600 p-4 shadow-xl flex-shrink-0 z-20">
        <div className="relative">
          <input
            ref={searchInputRef}
            type="text"
            placeholder="ابحث بالاسم أو الباركود..."
            className="w-full bg-white text-emerald-950 rounded-2xl py-4 px-12 text-lg font-bold shadow-inner focus:ring-4 focus:ring-emerald-300 transition-all border-none"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <Search className="absolute left-4 top-4.5 text-emerald-400" size={24} />
          {searchQuery && (
            <button onClick={() => setSearchQuery('')} className="absolute right-4 top-4.5 text-gray-300">
                <X size={24} />
            </button>
          )}
        </div>
      </header>

      {/* Primary Content View */}
      <main className="flex-grow overflow-y-auto p-2 pb-40">
        {view === 'pos' ? (
          <div className="grid grid-cols-1 gap-2">
            {filteredMedicines.map((med) => (
              <div 
                key={med.id}
                onClick={() => addToCart(med)}
                onContextMenu={(e) => { e.preventDefault(); setEditingMedicine(med); setIsEditOpen(true); }}
                className={`bg-white border-2 ${cart.has(med.id!) ? 'border-emerald-500 bg-emerald-50' : 'border-transparent'} p-4 rounded-2xl flex justify-between items-center active:scale-[0.97] transition-all shadow-sm cursor-pointer`}
              >
                <div className="flex-grow">
                  <div className="flex items-center gap-2">
                    <h3 className="font-black text-xl text-emerald-900">{med.name}</h3>
                    {cart.has(med.id!) && (
                        <span className="bg-emerald-600 text-white text-xs px-2 py-0.5 rounded-full font-bold">
                            × {cart.get(med.id!)?.quantity}
                        </span>
                    )}
                  </div>
                  <div className="flex gap-4 mt-1 opacity-70">
                    <span className="text-xs font-bold bg-emerald-100 px-2 py-0.5 rounded-lg">{med.barcode || 'بلا باركود'}</span>
                    <span className={`text-xs font-bold ${med.stock < 10 ? 'text-red-600 animate-pulse' : 'text-emerald-700'}`}>
                        المتاح: {med.stock}
                    </span>
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-2xl font-black text-emerald-700">{med.price.toFixed(2)}</div>
                  <div className="text-[10px] font-bold text-emerald-400">ج.م</div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="space-y-4 animate-in fade-in duration-300">
            {/* Sub-navigation */}
            <div className="flex bg-white p-1 rounded-2xl shadow-sm">
              <button onClick={() => setAccountingSubView('sales')} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${accountingSubView === 'sales' ? 'bg-emerald-600 text-white shadow-md' : 'text-emerald-600'}`}>
                <History size={18} /> المبيعات
              </button>
              <button onClick={() => setAccountingSubView('inventory')} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${accountingSubView === 'inventory' ? 'bg-emerald-600 text-white shadow-md' : 'text-emerald-600'}`}>
                <Filter size={18} /> تقرير النواقص
              </button>
            </div>

            {accountingSubView === 'sales' ? (
              <>
                <div className="grid grid-cols-2 gap-3">
                   <div className="bg-white p-5 rounded-3xl shadow-sm border-b-4 border-emerald-500">
                      <div className="flex items-center gap-2 text-emerald-600 mb-1">
                        <TrendingUp size={18}/> <span className="font-bold text-sm">مبيعات اليوم</span>
                      </div>
                      <div className="text-3xl font-black text-emerald-900">{todayStats.revenue.toFixed(2)}</div>
                   </div>
                   <div className="bg-white p-5 rounded-3xl shadow-sm border-b-4 border-amber-500">
                      <div className="flex items-center gap-2 text-amber-600 mb-1">
                        <Coins size={18}/> <span className="font-bold text-sm">صافي الربح</span>
                      </div>
                      <div className="text-3xl font-black text-emerald-900">{todayStats.profit.toFixed(2)}</div>
                   </div>
                </div>
                <div className="space-y-2 mt-4">
                    {todayStats.history.map(sale => (
                        <div key={sale.id} className="bg-white p-4 rounded-2xl flex justify-between items-center shadow-sm">
                            <div>
                                <div className="font-bold text-lg text-emerald-900">{sale.totalAmount.toFixed(2)} ج.م</div>
                                <div className="text-xs text-emerald-500 font-bold">{formatTime(sale.timestamp)}</div>
                            </div>
                            <div className="text-[10px] text-gray-400 max-w-[150px] truncate text-left dir-ltr">
                                {JSON.parse(sale.itemsJson).map((i:any) => i.name).join(', ')}
                            </div>
                        </div>
                    ))}
                </div>
              </>
            ) : (
              <div className="space-y-4">
                {/* Advanced Filtering UI */}
                <div className="bg-white p-4 rounded-3xl shadow-sm space-y-4">
                  <div className="flex flex-wrap gap-2">
                    <button onClick={() => setCategoryFilter('all')} className={`px-4 py-2 rounded-full text-xs font-bold transition-all ${categoryFilter === 'all' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-emerald-50 text-emerald-600 border'}`}>الكل</button>
                    {categories.map(cat => (
                      <button key={cat} onClick={() => setCategoryFilter(cat)} className={`px-4 py-2 rounded-full text-xs font-bold transition-all ${categoryFilter === cat ? 'bg-emerald-600 text-white shadow-lg' : 'bg-emerald-50 text-emerald-600 border'}`}>{cat}</button>
                    ))}
                  </div>
                  <div className="flex gap-2">
                    <button onClick={() => setExpiryFilter('all')} className={`flex-1 py-3 rounded-2xl text-xs font-bold ${expiryFilter === 'all' ? 'bg-emerald-600 text-white' : 'bg-emerald-50 text-emerald-600'}`}>الكل</button>
                    <button onClick={() => setExpiryFilter('soon')} className={`flex-1 py-3 rounded-2xl text-xs font-bold ${expiryFilter === 'soon' ? 'bg-orange-500 text-white' : 'bg-orange-50 text-orange-600'}`}>قريباً</button>
                    <button onClick={() => setExpiryFilter('expired')} className={`flex-1 py-3 rounded-2xl text-xs font-bold ${expiryFilter === 'expired' ? 'bg-red-500 text-white' : 'bg-red-50 text-red-600'}`}>منتهي</button>
                  </div>
                </div>

                <div className="space-y-2">
                  {analyzedInventory.map(med => (
                      <div key={med.id} onClick={() => { setEditingMedicine(med); setIsEditOpen(true); }} className="bg-white p-4 rounded-2xl flex justify-between items-center shadow-sm border-r-8" style={{ borderRightColor: new Date(med.expiryDate) <= new Date() ? '#ef4444' : '#10b981' }}>
                        <div>
                          <div className="font-bold text-emerald-900">{med.name}</div>
                          <div className="text-[10px] text-emerald-500">تنتهي: {formatDate(med.expiryDate)}</div>
                        </div>
                        <div className="text-right">
                          <div className={`font-black ${med.stock < 5 ? 'text-red-500' : 'text-emerald-700'}`}>{med.stock} متاح</div>
                        </div>
                      </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {/* Persistent Checkout Bar */}
      {view === 'pos' && cart.size > 0 && (
        <div className="fixed bottom-24 left-0 right-0 p-4 pointer-events-none z-50">
            <div className="max-w-md mx-auto bg-emerald-900/95 backdrop-blur-xl text-white p-4 rounded-[32px] flex items-center justify-between shadow-2xl pointer-events-auto border border-emerald-500/20">
                <div className="flex items-center gap-3">
                    <button onClick={clearCart} className="bg-red-500/20 text-red-400 p-3 rounded-2xl active:scale-90 transition-transform"><Trash2 size={24} /></button>
                    <div>
                        <div className="text-2xl font-black">{cartTotal.toFixed(2)} <span className="text-xs font-normal opacity-60">ج.م</span></div>
                        <div className="text-[10px] font-bold opacity-40 uppercase tracking-widest">{cartItemsCount} صنف في السلة</div>
                    </div>
                </div>
                <button onClick={handleCheckout} className="bg-emerald-500 hover:bg-emerald-400 text-white px-10 py-4 rounded-2xl font-black text-xl active:scale-95 transition-all shadow-lg shadow-emerald-500/20">تأكيد البيع</button>
            </div>
        </div>
      )}

      {/* Floating Status Notification */}
      {checkoutResult && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[60] px-8 py-4 rounded-3xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top duration-300 font-bold text-lg
            ${checkoutResult.status === 'success' ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'}`}>
          {checkoutResult.status === 'success' ? <CheckCircle2 /> : <AlertCircle />}
          {checkoutResult.msg}
        </div>
      )}

      {/* Navigation */}
      <nav className="bg-white border-t border-emerald-100 flex justify-around p-3 pb-10 flex-shrink-0 z-40">
        <button onClick={() => setView('pos')} className={`flex flex-col items-center gap-1 transition-all ${view === 'pos' ? 'text-emerald-600 scale-110' : 'text-gray-300'}`}>
          <Package size={28} strokeWidth={view === 'pos' ? 3 : 2} /> <span className="text-[10px] font-black">الكاشير</span>
        </button>
        <div className="relative -mt-12">
            <button onClick={() => { setEditingMedicine(null); setIsEditOpen(true); }} className="bg-emerald-500 text-white p-6 rounded-full shadow-2xl shadow-emerald-200 active:scale-90 transition-transform"><Plus size={36} strokeWidth={4} /></button>
        </div>
        <button onClick={() => setView('accounting')} className={`flex flex-col items-center gap-1 transition-all ${view === 'accounting' ? 'text-emerald-600 scale-110' : 'text-gray-300'}`}>
          <BarChart3 size={28} strokeWidth={view === 'accounting' ? 3 : 2} /> <span className="text-[10px] font-black">الحسابات</span>
        </button>
      </nav>

      {/* Enhanced Modal */}
      {isEditOpen && (
        <MedicineDialog categories={categories} initialData={editingMedicine} onSave={handleSaveMedicine} onClose={() => setIsEditOpen(false)} onDelete={handleDeleteMedicine} />
      )}
    </div>
  );
};

const MedicineDialog: React.FC<{
  initialData: Medicine | null; categories: string[];
  onSave: (data: Medicine) => void; onClose: () => void; onDelete: (id: number) => void;
}> = ({ initialData, categories, onSave, onClose, onDelete }) => {
  const [formData, setFormData] = useState<Medicine>(
    initialData || { name: '', barcode: '', price: 0, costPrice: 0, stock: 0, category: 'عام', expiryDate: new Date().toISOString().split('T')[0] }
  );

  const nameRef = useRef<HTMLInputElement>(null);
  useEffect(() => { if (nameRef.current) nameRef.current.focus(); }, []);

  return (
    <div className="fixed inset-0 bg-emerald-950/50 backdrop-blur-md z-[100] flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-[48px] overflow-hidden shadow-2xl animate-in zoom-in-95 max-h-[90vh] flex flex-col">
        <div className="bg-emerald-600 p-8 text-white flex justify-between items-center shrink-0">
          <h2 className="text-3xl font-black">{initialData ? 'تعديل الصنف' : 'صنف جديد'}</h2>
          <button onClick={onClose} className="p-2 bg-white/20 rounded-full"><X size={24}/></button>
        </div>
        <form onSubmit={(e) => { e.preventDefault(); onSave(formData); }} className="p-8 space-y-5 overflow-y-auto">
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900/50 block px-1 uppercase tracking-widest">الاسم التجاري</label>
            <input ref={nameRef} type="text" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 focus:bg-white outline-none" value={formData.name} required onChange={e => setFormData({...formData, name: e.target.value})}/>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-sm font-black text-emerald-900/50 block px-1">سعر البيع</label>
              <input type="number" step="0.01" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.price} required onChange={e => setFormData({...formData, price: parseFloat(e.target.value) || 0})}/>
            </div>
            <div className="space-y-1">
              <label className="text-sm font-black text-emerald-900/50 block px-1">سعر التكلفة</label>
              <input type="number" step="0.01" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.costPrice} required onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value) || 0})}/>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
             <div className="space-y-1">
                <label className="text-sm font-black text-emerald-900/50 block px-1">المخزون</label>
                <input type="number" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.stock} required onChange={e => setFormData({...formData, stock: parseInt(e.target.value) || 0})}/>
              </div>
              <div className="space-y-1">
                <label className="text-sm font-black text-emerald-900/50 block px-1">التصنيف</label>
                <input type="text" list="cats" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}/>
                <datalist id="cats">{categories.map(c => <option key={c} value={c}/>)}</datalist>
              </div>
          </div>
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900/50 block px-1">الباركود</label>
            <input type="text" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.barcode} onChange={e => setFormData({...formData, barcode: e.target.value})}/>
          </div>
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900/50 block px-1">الصلاحية</label>
            <input type="date" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.expiryDate} required onChange={e => setFormData({...formData, expiryDate: e.target.value})}/>
          </div>
          <div className="flex gap-4 pt-4 shrink-0">
            <button type="submit" className="flex-grow bg-emerald-600 text-white py-5 rounded-3xl font-black text-xl shadow-xl active:scale-95 transition-all">حفظ البيانات</button>
            {initialData?.id && (
              <button type="button" onClick={() => onDelete(initialData.id!)} className="bg-red-50 text-red-600 p-5 rounded-3xl active:scale-95 transition-all"><Trash2 size={24} /></button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default App;

import { Dexie, Table } from 'dexie';
import { Medicine, Sale } from './types';

// Define the database class extending Dexie
export class PharmacyDB extends Dexie {
  // Explicitly define tables with their types and primary key types (number)
  medicines!: Table<Medicine, number>;
  sales!: Table<Sale, number>;

  constructor() {
    super('PharmacyDB');
  }
}

export const db = new PharmacyDB();

// Configure the database version and schema outside the constructor 
// to ensure proper type inference of Dexie methods on the instance.
db.version(2).stores({
  // Added indices for name and barcode to ensure O(1) or O(log n) search speed
  medicines: '++id, *name, *barcode, stock, expiryDate, category',
  sales: '++id, timestamp'
});

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Search, Plus, Package, BarChart3, ShoppingCart, X, Save, Trash2, CheckCircle2, History, TrendingUp, AlertCircle, Filter, Calendar, Tag, Coins } from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem } from './types';

const formatDate = (date: string) => new Date(date).toLocaleDateString('ar-EG');
const formatTime = (ts: number) => new Date(ts).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' });

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('pos');
  const [accountingSubView, setAccountingSubView] = useState<'sales' | 'inventory'>('sales');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map<number, CartItem>());
  const [isEditOpen, setIsEditOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [checkoutResult, setCheckoutResult] = useState<{status: 'success' | 'error', msg: string} | null>(null);

  const [categoryFilter, setCategoryFilter] = useState<string>('all');
  const [expiryFilter, setExpiryFilter] = useState<'all' | 'soon' | 'expired'>('all');

  const searchInputRef = useRef<HTMLInputElement>(null);

  const loadData = useCallback(async () => {
    // Optimization: Order medicines by ID descending to show newest first
    const [allMeds, allSales] = await Promise.all([
      db.medicines.reverse().toArray(),
      db.sales.orderBy('timestamp').reverse().toArray()
    ]);
    setMedicines(allMeds);
    setSalesHistory(allSales);
  }, []);

  useEffect(() => {
    loadData();
    if (searchInputRef.current) searchInputRef.current.focus();
  }, [loadData]);

  const addToCart = (med: Medicine) => {
    if (med.id === undefined) return;

    // Safety check: Stock 0
    if (med.stock <= 0) {
      setCheckoutResult({status: 'error', msg: 'عذراً، هذا الصنف نفذ من المخزن'});
      setTimeout(() => setCheckoutResult(null), 2000);
      return;
    }

    const newCart = new Map<number, CartItem>(cart);
    const existing = newCart.get(med.id);
    const currentQty = existing?.quantity || 0;

    // Safety check: Exceeding stock
    if (currentQty >= med.stock) {
        setCheckoutResult({status: 'error', msg: 'الكمية المختارة تتجاوز المتاح في المخزن'});
        setTimeout(() => setCheckoutResult(null), 2000);
        return;
    }

    // Logical Improvement: Merge duplicates instead of adding new lines
    newCart.set(med.id, { medicine: med, quantity: currentQty + 1 });
    setCart(newCart);

    if (navigator.vibrate) navigator.vibrate(40);
  };

  const clearCart = () => {
    if (confirm('هل تريد مسح جميع محتويات السلة؟')) {
      setCart(new Map());
    }
  };

  const handleCheckout = async () => {
    if (cart.size === 0) return;

    try {
      // Fix: Explicitly type items and reduction results to avoid "unknown" operator errors
      const items: CartItem[] = Array.from(cart.values());
      const totalAmount: number = items.reduce<number>((sum, item) => sum + (item.medicine.price * item.quantity), 0);
      const totalCost: number = items.reduce<number>((sum, item) => sum + (item.medicine.costPrice * item.quantity), 0);

      // ATOMIC TRANSACTION: Ensuring stock update and sale logging are inseparable
      // Fix: Cast db to any to ensure transaction access if standard inheritance is obscured by compiler
      await (db as any).transaction('rw', [db.medicines, db.sales], async () => {
        for (const item of items) {
          const currentMed = await db.medicines.get(item.medicine.id!);
          if (!currentMed || currentMed.stock < item.quantity) {
            throw new Error(`نقص مفاجئ في مخزون ${item.medicine.name}`);
          }
          await db.medicines.update(item.medicine.id!, { 
            stock: currentMed.stock - item.quantity 
          });
        }

        await db.sales.add({
          totalAmount,
          totalCost,
          timestamp: Date.now(),
          itemsJson: JSON.stringify(items.map(i => ({ 
            name: i.medicine.name, 
            qty: i.quantity, 
            price: i.medicine.price,
            cost: i.medicine.costPrice
          })))
        });
      });

      setCart(new Map());
      // Fix: totalAmount is now explicitly number, toFixed is available
      setCheckoutResult({status: 'success', msg: `تمت عملية البيع! الإجمالي: ${totalAmount.toFixed(2)}`});
      loadData();
    } catch (err: any) {
      setCheckoutResult({status: 'error', msg: err.message || 'خطأ غير متوقع'});
    }
    setTimeout(() => setCheckoutResult(null), 3000);
  };

  const todayStats = useMemo(() => {
    const startOfDay = new Date().setHours(0, 0, 0, 0);
    const todaySales = salesHistory.filter(s => s.timestamp >= startOfDay);
    const revenue = todaySales.reduce((sum, s) => sum + s.totalAmount, 0);
    const cost = todaySales.reduce((sum, s) => sum + (s.totalCost || 0), 0);
    return { count: todaySales.length, revenue, profit: revenue - cost, history: todaySales };
  }, [salesHistory]);

  const categories = useMemo(() => {
    const cats = new Set(medicines.map(m => m.category || 'عام'));
    return Array.from(cats);
  }, [medicines]);

  const filteredMedicines = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    // High-speed filtering on in-memory array (suitable for <5000 items)
    return medicines.filter(m => 
      m.name.toLowerCase().includes(q) || 
      m.barcode.toLowerCase().includes(q)
    );
  }, [medicines, searchQuery]);

  const analyzedInventory = useMemo(() => {
    const now = new Date();
    const threeMonthsLater = new Date();
    threeMonthsLater.setMonth(now.getMonth() + 3);

    return medicines.filter(m => {
      const matchesCategory = categoryFilter === 'all' || (m.category || 'عام') === categoryFilter;
      const expDate = new Date(m.expiryDate);
      let matchesExpiry = true;
      if (expiryFilter === 'soon') matchesExpiry = expDate > now && expDate <= threeMonthsLater;
      else if (expiryFilter === 'expired') matchesExpiry = expDate <= now;
      return matchesCategory && matchesExpiry;
    });
  }, [medicines, categoryFilter, expiryFilter]);

  const handleSaveMedicine = async (data: Medicine) => {
    if (data.id) await db.medicines.update(data.id, data);
    else await db.medicines.add(data);
    setIsEditOpen(false);
    setEditingMedicine(null);
    loadData();
  };

  const handleDeleteMedicine = async (id: number) => {
    if (confirm('حذف الدواء نهائياً من النظام؟')) {
      await db.medicines.delete(id);
      setIsEditOpen(false);
      loadData();
    }
  };

  // Fix: Explicitly type array from Map values and ensure reduce uses correct types to avoid "unknown" errors
  const cartItemsArr: CartItem[] = Array.from(cart.values());
  const cartTotal = cartItemsArr.reduce<number>((sum, item) => sum + (item.medicine.price * item.quantity), 0);
  const cartItemsCount = cartItemsArr.reduce<number>((sum, item) => sum + item.quantity, 0);

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-emerald-50 text-emerald-950 select-none">
      {/* Dynamic Header */}
      <header className="bg-emerald-600 p-4 shadow-xl flex-shrink-0 z-20">
        <div className="relative">
          <input
            ref={searchInputRef}
            type="text"
            placeholder="ابحث بالاسم أو الباركود..."
            className="w-full bg-white text-emerald-950 rounded-2xl py-4 px-12 text-lg font-bold shadow-inner focus:ring-4 focus:ring-emerald-300 transition-all border-none"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <Search className="absolute left-4 top-4.5 text-emerald-400" size={24} />
          {searchQuery && (
            <button onClick={() => setSearchQuery('')} className="absolute right-4 top-4.5 text-gray-300">
                <X size={24} />
            </button>
          )}
        </div>
      </header>

      {/* Primary Content View */}
      <main className="flex-grow overflow-y-auto p-2 pb-40">
        {view === 'pos' ? (
          <div className="grid grid-cols-1 gap-2">
            {filteredMedicines.map((med) => (
              <div 
                key={med.id}
                onClick={() => addToCart(med)}
                onContextMenu={(e) => { e.preventDefault(); setEditingMedicine(med); setIsEditOpen(true); }}
                className={`bg-white border-2 ${cart.has(med.id!) ? 'border-emerald-500 bg-emerald-50' : 'border-transparent'} p-4 rounded-2xl flex justify-between items-center active:scale-[0.97] transition-all shadow-sm cursor-pointer`}
              >
                <div className="flex-grow">
                  <div className="flex items-center gap-2">
                    <h3 className="font-black text-xl text-emerald-900">{med.name}</h3>
                    {cart.has(med.id!) && (
                        <span className="bg-emerald-600 text-white text-xs px-2 py-0.5 rounded-full font-bold">
                            × {cart.get(med.id!)?.quantity}
                        </span>
                    )}
                  </div>
                  <div className="flex gap-4 mt-1 opacity-70">
                    <span className="text-xs font-bold bg-emerald-100 px-2 py-0.5 rounded-lg">{med.barcode || 'بلا باركود'}</span>
                    <span className={`text-xs font-bold ${med.stock < 10 ? 'text-red-600 animate-pulse' : 'text-emerald-700'}`}>
                        المتاح: {med.stock}
                    </span>
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-2xl font-black text-emerald-700">{med.price.toFixed(2)}</div>
                  <div className="text-[10px] font-bold text-emerald-400">ج.م</div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="space-y-4 animate-in fade-in duration-300">
            {/* Sub-navigation */}
            <div className="flex bg-white p-1 rounded-2xl shadow-sm">
              <button onClick={() => setAccountingSubView('sales')} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${accountingSubView === 'sales' ? 'bg-emerald-600 text-white shadow-md' : 'text-emerald-600'}`}>
                <History size={18} /> المبيعات
              </button>
              <button onClick={() => setAccountingSubView('inventory')} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${accountingSubView === 'inventory' ? 'bg-emerald-600 text-white shadow-md' : 'text-emerald-600'}`}>
                <Filter size={18} /> تقرير النواقص
              </button>
            </div>

            {accountingSubView === 'sales' ? (
              <>
                <div className="grid grid-cols-2 gap-3">
                   <div className="bg-white p-5 rounded-3xl shadow-sm border-b-4 border-emerald-500">
                      <div className="flex items-center gap-2 text-emerald-600 mb-1">
                        <TrendingUp size={18}/> <span className="font-bold text-sm">مبيعات اليوم</span>
                      </div>
                      <div className="text-3xl font-black text-emerald-900">{todayStats.revenue.toFixed(2)}</div>
                   </div>
                   <div className="bg-white p-5 rounded-3xl shadow-sm border-b-4 border-amber-500">
                      <div className="flex items-center gap-2 text-amber-600 mb-1">
                        <Coins size={18}/> <span className="font-bold text-sm">صافي الربح</span>
                      </div>
                      <div className="text-3xl font-black text-emerald-900">{todayStats.profit.toFixed(2)}</div>
                   </div>
                </div>
                <div className="space-y-2 mt-4">
                    {todayStats.history.map(sale => (
                        <div key={sale.id} className="bg-white p-4 rounded-2xl flex justify-between items-center shadow-sm">
                            <div>
                                <div className="font-bold text-lg text-emerald-900">{sale.totalAmount.toFixed(2)} ج.م</div>
                                <div className="text-xs text-emerald-500 font-bold">{formatTime(sale.timestamp)}</div>
                            </div>
                            <div className="text-[10px] text-gray-400 max-w-[150px] truncate text-left dir-ltr">
                                {JSON.parse(sale.itemsJson).map((i:any) => i.name).join(', ')}
                            </div>
                        </div>
                    ))}
                </div>
              </>
            ) : (
              <div className="space-y-4">
                {/* Advanced Filtering UI */}
                <div className="bg-white p-4 rounded-3xl shadow-sm space-y-4">
                  <div className="flex flex-wrap gap-2">
                    <button onClick={() => setCategoryFilter('all')} className={`px-4 py-2 rounded-full text-xs font-bold transition-all ${categoryFilter === 'all' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-emerald-50 text-emerald-600 border'}`}>الكل</button>
                    {categories.map(cat => (
                      <button key={cat} onClick={() => setCategoryFilter(cat)} className={`px-4 py-2 rounded-full text-xs font-bold transition-all ${categoryFilter === cat ? 'bg-emerald-600 text-white shadow-lg' : 'bg-emerald-50 text-emerald-600 border'}`}>{cat}</button>
                    ))}
                  </div>
                  <div className="flex gap-2">
                    <button onClick={() => setExpiryFilter('all')} className={`flex-1 py-3 rounded-2xl text-xs font-bold ${expiryFilter === 'all' ? 'bg-emerald-600 text-white' : 'bg-emerald-50 text-emerald-600'}`}>الكل</button>
                    <button onClick={() => setExpiryFilter('soon')} className={`flex-1 py-3 rounded-2xl text-xs font-bold ${expiryFilter === 'soon' ? 'bg-orange-500 text-white' : 'bg-orange-50 text-orange-600'}`}>قريباً</button>
                    <button onClick={() => setExpiryFilter('expired')} className={`flex-1 py-3 rounded-2xl text-xs font-bold ${expiryFilter === 'expired' ? 'bg-red-500 text-white' : 'bg-red-50 text-red-600'}`}>منتهي</button>
                  </div>
                </div>

                <div className="space-y-2">
                  {analyzedInventory.map(med => (
                      <div key={med.id} onClick={() => { setEditingMedicine(med); setIsEditOpen(true); }} className="bg-white p-4 rounded-2xl flex justify-between items-center shadow-sm border-r-8" style={{ borderRightColor: new Date(med.expiryDate) <= new Date() ? '#ef4444' : '#10b981' }}>
                        <div>
                          <div className="font-bold text-emerald-900">{med.name}</div>
                          <div className="text-[10px] text-emerald-500">تنتهي: {formatDate(med.expiryDate)}</div>
                        </div>
                        <div className="text-right">
                          <div className={`font-black ${med.stock < 5 ? 'text-red-500' : 'text-emerald-700'}`}>{med.stock} متاح</div>
                        </div>
                      </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {/* Persistent Checkout Bar */}
      {view === 'pos' && cart.size > 0 && (
        <div className="fixed bottom-24 left-0 right-0 p-4 pointer-events-none z-50">
            <div className="max-w-md mx-auto bg-emerald-900/95 backdrop-blur-xl text-white p-4 rounded-[32px] flex items-center justify-between shadow-2xl pointer-events-auto border border-emerald-500/20">
                <div className="flex items-center gap-3">
                    <button onClick={clearCart} className="bg-red-500/20 text-red-400 p-3 rounded-2xl active:scale-90 transition-transform"><Trash2 size={24} /></button>
                    <div>
                        <div className="text-2xl font-black">{cartTotal.toFixed(2)} <span className="text-xs font-normal opacity-60">ج.م</span></div>
                        <div className="text-[10px] font-bold opacity-40 uppercase tracking-widest">{cartItemsCount} صنف في السلة</div>
                    </div>
                </div>
                <button onClick={handleCheckout} className="bg-emerald-500 hover:bg-emerald-400 text-white px-10 py-4 rounded-2xl font-black text-xl active:scale-95 transition-all shadow-lg shadow-emerald-500/20">تأكيد البيع</button>
            </div>
        </div>
      )}

      {/* Floating Status Notification */}
      {checkoutResult && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[60] px-8 py-4 rounded-3xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top duration-300 font-bold text-lg
            ${checkoutResult.status === 'success' ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'}`}>
          {checkoutResult.status === 'success' ? <CheckCircle2 /> : <AlertCircle />}
          {checkoutResult.msg}
        </div>
      )}

      {/* Navigation */}
      <nav className="bg-white border-t border-emerald-100 flex justify-around p-3 pb-10 flex-shrink-0 z-40">
        <button onClick={() => setView('pos')} className={`flex flex-col items-center gap-1 transition-all ${view === 'pos' ? 'text-emerald-600 scale-110' : 'text-gray-300'}`}>
          <Package size={28} strokeWidth={view === 'pos' ? 3 : 2} /> <span className="text-[10px] font-black">الكاشير</span>
        </button>
        <div className="relative -mt-12">
            <button onClick={() => { setEditingMedicine(null); setIsEditOpen(true); }} className="bg-emerald-500 text-white p-6 rounded-full shadow-2xl shadow-emerald-200 active:scale-90 transition-transform"><Plus size={36} strokeWidth={4} /></button>
        </div>
        <button onClick={() => setView('accounting')} className={`flex flex-col items-center gap-1 transition-all ${view === 'accounting' ? 'text-emerald-600 scale-110' : 'text-gray-300'}`}>
          <BarChart3 size={28} strokeWidth={view === 'accounting' ? 3 : 2} /> <span className="text-[10px] font-black">الحسابات</span>
        </button>
      </nav>

      {/* Enhanced Modal */}
      {isEditOpen && (
        <MedicineDialog categories={categories} initialData={editingMedicine} onSave={handleSaveMedicine} onClose={() => setIsEditOpen(false)} onDelete={handleDeleteMedicine} />
      )}
    </div>
  );
};

const MedicineDialog: React.FC<{
  initialData: Medicine | null; categories: string[];
  onSave: (data: Medicine) => void; onClose: () => void; onDelete: (id: number) => void;
}> = ({ initialData, categories, onSave, onClose, onDelete }) => {
  const [formData, setFormData] = useState<Medicine>(
    initialData || { name: '', barcode: '', price: 0, costPrice: 0, stock: 0, category: 'عام', expiryDate: new Date().toISOString().split('T')[0] }
  );

  const nameRef = useRef<HTMLInputElement>(null);
  useEffect(() => { if (nameRef.current) nameRef.current.focus(); }, []);

  return (
    <div className="fixed inset-0 bg-emerald-950/50 backdrop-blur-md z-[100] flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-[48px] overflow-hidden shadow-2xl animate-in zoom-in-95 max-h-[90vh] flex flex-col">
        <div className="bg-emerald-600 p-8 text-white flex justify-between items-center shrink-0">
          <h2 className="text-3xl font-black">{initialData ? 'تعديل الصنف' : 'صنف جديد'}</h2>
          <button onClick={onClose} className="p-2 bg-white/20 rounded-full"><X size={24}/></button>
        </div>
        <form onSubmit={(e) => { e.preventDefault(); onSave(formData); }} className="p-8 space-y-5 overflow-y-auto">
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900/50 block px-1 uppercase tracking-widest">الاسم التجاري</label>
            <input ref={nameRef} type="text" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 focus:bg-white outline-none" value={formData.name} required onChange={e => setFormData({...formData, name: e.target.value})}/>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-sm font-black text-emerald-900/50 block px-1">سعر البيع</label>
              <input type="number" step="0.01" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.price} required onChange={e => setFormData({...formData, price: parseFloat(e.target.value) || 0})}/>
            </div>
            <div className="space-y-1">
              <label className="text-sm font-black text-emerald-900/50 block px-1">سعر التكلفة</label>
              <input type="number" step="0.01" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.costPrice} required onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value) || 0})}/>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
             <div className="space-y-1">
                <label className="text-sm font-black text-emerald-900/50 block px-1">المخزون</label>
                <input type="number" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.stock} required onChange={e => setFormData({...formData, stock: parseInt(e.target.value) || 0})}/>
              </div>
              <div className="space-y-1">
                <label className="text-sm font-black text-emerald-900/50 block px-1">التصنيف</label>
                <input type="text" list="cats" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}/>
                <datalist id="cats">{categories.map(c => <option key={c} value={c}/>)}</datalist>
              </div>
          </div>
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900/50 block px-1">الباركود</label>
            <input type="text" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.barcode} onChange={e => setFormData({...formData, barcode: e.target.value})}/>
          </div>
          <div className="space-y-1">
            <label className="text-sm font-black text-emerald-900/50 block px-1">الصلاحية</label>
            <input type="date" className="w-full bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.expiryDate} required onChange={e => setFormData({...formData, expiryDate: e.target.value})}/>
          </div>
          <div className="flex gap-4 pt-4 shrink-0">
            <button type="submit" className="flex-grow bg-emerald-600 text-white py-5 rounded-3xl font-black text-xl shadow-xl active:scale-95 transition-all">حفظ البيانات</button>
            {initialData?.id && (
              <button type="button" onClick={() => onDelete(initialData.id!)} className="bg-red-50 text-red-600 p-5 rounded-3xl active:scale-95 transition-all"><Trash2 size={24} /></button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default App;

export interface Medicine {
  id?: number;
  name: string;
  barcode: string;
  price: number;
  costPrice: number;
  stock: number;
  category: string;
  expiryDate: string;
}

export type PaymentMethod = 'cash' | 'bank' | 'credit';

export interface Sale {
  id?: number;
  totalAmount: number;
  totalCost: number;
  timestamp: number;
  itemsJson: string; // List of {name, price, costPrice, quantity}
  paymentMethod: PaymentMethod;
}

export interface CartItem {
  medicine: Medicine;
  quantity: number;
}

export type ViewType = 'pos' | 'accounting';

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Search, Plus, Package, BarChart3, ShoppingCart, X, Trash2, CheckCircle2, History, TrendingUp, AlertCircle, Filter, Calendar, Tag, Coins, CreditCard, Wallet, UserMinus } from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem, PaymentMethod } from './types';

const formatDate = (date: string) => new Date(date).toLocaleDateString('ar-EG');
const formatTime = (ts: number) => new Date(ts).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' });

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('pos');
  const [accountingSubView, setAccountingSubView] = useState<'sales' | 'inventory'>('sales');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map<number, CartItem>());
  const [selectedPayment, setSelectedPayment] = useState<PaymentMethod>('cash');

  const [isEditOpen, setIsEditOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [checkoutResult, setCheckoutResult] = useState<{status: 'success' | 'error', msg: string} | null>(null);

  // Inventory Filters
  const [invCategoryFilter, setInvCategoryFilter] = useState<string>('all');
  const [invStockFilter, setInvStockFilter] = useState<'all' | 'low' | 'out'>('all');
  const [invExpiryFilter, setInvExpiryFilter] = useState<'all' | 'soon' | 'expired'>('all');

  // Sales Filters
  const [salesDateFilter, setSalesDateFilter] = useState<string>(new Date().toISOString().split('T')[0]);
  const [salesPaymentFilter, setSalesPaymentFilter] = useState<'all' | PaymentMethod>('all');

  const searchInputRef = useRef<HTMLInputElement>(null);

  const loadData = useCallback(async () => {
    const [allMeds, allSales] = await Promise.all([
      db.medicines.reverse().toArray(),
      db.sales.orderBy('timestamp').reverse().toArray()
    ]);
    setMedicines(allMeds);
    setSalesHistory(allSales);
  }, []);

  useEffect(() => {
    loadData();
    if (searchInputRef.current) searchInputRef.current.focus();
  }, [loadData]);

  const addToCart = (med: Medicine) => {
    if (med.id === undefined) return;
    if (med.stock <= 0) {
      setCheckoutResult({status: 'error', msg: 'عذراً، هذا الصنف نفذ من المخزن'});
      setTimeout(() => setCheckoutResult(null), 2000);
      return;
    }
    const newCart = new Map<number, CartItem>(cart);
    const existing = newCart.get(med.id);
    const currentQty = existing?.quantity || 0;

    if (currentQty >= med.stock) {
        setCheckoutResult({status: 'error', msg: 'الكمية المختارة تتجاوز المتاح'});
        setTimeout(() => setCheckoutResult(null), 2000);
        return;
    }
    newCart.set(med.id, { medicine: med, quantity: currentQty + 1 });
    setCart(newCart);
    if (navigator.vibrate) navigator.vibrate(40);
  };

  const clearCart = () => { if (confirm('مسح السلة؟')) setCart(new Map()); };

  const handleCheckout = async () => {
    if (cart.size === 0) return;
    try {
      const items: CartItem[] = Array.from(cart.values());
      const totalAmount: number = items.reduce<number>((sum, item) => sum + (item.medicine.price * item.quantity), 0);
      const totalCost: number = items.reduce<number>((sum, item) => sum + (item.medicine.costPrice * item.quantity), 0);

      await (db as any).transaction('rw', [db.medicines, db.sales], async () => {
        for (const item of items) {
          const currentMed = await db.medicines.get(item.medicine.id!);
          if (!currentMed || currentMed.stock < item.quantity) throw new Error(`نقص مخزون ${item.medicine.name}`);
          await db.medicines.update(item.medicine.id!, { stock: currentMed.stock - item.quantity });
        }
        await db.sales.add({
          totalAmount, totalCost, timestamp: Date.now(),
          paymentMethod: selectedPayment,
          itemsJson: JSON.stringify(items.map(i => ({ name: i.medicine.name, qty: i.quantity, price: i.medicine.price, cost: i.medicine.costPrice })))
        });
      });
      setCart(new Map());
      setCheckoutResult({status: 'success', msg: `تم البيع (${selectedPayment === 'cash' ? 'كاش' : selectedPayment === 'bank' ? 'بنك' : 'آجل'})`});
      loadData();
    } catch (err: any) {
      setCheckoutResult({status: 'error', msg: err.message || 'خطأ غير متوقع'});
    }
    setTimeout(() => setCheckoutResult(null), 3000);
  };

  // --- Filtering Logic ---
  const filteredInventory = useMemo(() => {
    const now = new Date();
    const soon = new Date(); soon.setMonth(now.getMonth() + 3);

    return medicines.filter(m => {
      const matchesCat = invCategoryFilter === 'all' || m.category === invCategoryFilter;
      const matchesStock = invStockFilter === 'all' || (invStockFilter === 'low' && m.stock > 0 && m.stock < 10) || (invStockFilter === 'out' && m.stock <= 0);
      const expDate = new Date(m.expiryDate);
      const matchesExp = invExpiryFilter === 'all' || (invExpiryFilter === 'soon' && expDate > now && expDate <= soon) || (invExpiryFilter === 'expired' && expDate <= now);
      return matchesCat && matchesStock && matchesExp;
    });
  }, [medicines, invCategoryFilter, invStockFilter, invExpiryFilter]);

  const filteredSales = useMemo(() => {
    return salesHistory.filter(s => {
      const sDate = new Date(s.timestamp).toISOString().split('T')[0];
      const matchesDate = !salesDateFilter || sDate === salesDateFilter;
      const matchesPayment = salesPaymentFilter === 'all' || s.paymentMethod === salesPaymentFilter;
      return matchesDate && matchesPayment;
    });
  }, [salesHistory, salesDateFilter, salesPaymentFilter]);

  const salesStats = useMemo(() => {
    const revenue = filteredSales.reduce((sum, s) => sum + s.totalAmount, 0);
    const cost = filteredSales.reduce((sum, s) => sum + (s.totalCost || 0), 0);
    return { revenue, profit: revenue - cost, count: filteredSales.length };
  }, [filteredSales]);

  const categories = useMemo(() => Array.from(new Set(medicines.map(m => m.category || 'عام'))), [medicines]);

  const medicinesForPOS = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    return medicines.filter(m => m.name.toLowerCase().includes(q) || m.barcode.toLowerCase().includes(q));
  }, [medicines, searchQuery]);

  const handleSaveMedicine = async (data: Medicine) => {
    if (data.id) await db.medicines.update(data.id, data);
    else await db.medicines.add(data);
    setIsEditOpen(false); setEditingMedicine(null); loadData();
  };

  const handleDeleteMedicine = async (id: number) => {
    if (confirm('حذف نهائي؟')) { await db.medicines.delete(id); setIsEditOpen(false); loadData(); }
  };

  const cartTotal = Array.from(cart.values()).reduce<number>((sum, item) => sum + (item.medicine.price * item.quantity), 0);
  const cartItemsCount = Array.from(cart.values()).reduce<number>((sum, item) => sum + item.quantity, 0);

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-emerald-50 text-emerald-950 select-none">
      <header className="bg-emerald-600 p-4 shadow-xl z-20 shrink-0">
        <div className="relative">
          <input ref={searchInputRef} type="text" placeholder="ابحث باسم الدواء أو الباركود..." className="w-full bg-white text-emerald-950 rounded-2xl py-4 px-12 text-lg font-bold shadow-inner focus:ring-4 focus:ring-emerald-300 transition-all border-none" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} />
          <Search className="absolute left-4 top-4.5 text-emerald-400" size={24} />
          {searchQuery && <button onClick={() => setSearchQuery('')} className="absolute right-4 top-4.5 text-gray-300"><X size={24} /></button>}
        </div>
      </header>

      <main className="flex-grow overflow-y-auto p-2 pb-40">
        {view === 'pos' ? (
          <div className="grid grid-cols-1 gap-2">
            {medicinesForPOS.map((med) => (
              <div key={med.id} onClick={() => addToCart(med)} onContextMenu={(e) => { e.preventDefault(); setEditingMedicine(med); setIsEditOpen(true); }} className={`bg-white border-2 ${cart.has(med.id!) ? 'border-emerald-500 bg-emerald-50' : 'border-transparent'} p-4 rounded-2xl flex justify-between items-center active:scale-[0.97] transition-all shadow-sm cursor-pointer`}>
                <div className="flex-grow">
                  <div className="flex items-center gap-2">
                    <h3 className="font-black text-xl text-emerald-900">{med.name}</h3>
                    {cart.has(med.id!) && <span className="bg-emerald-600 text-white text-xs px-2 py-0.5 rounded-full font-bold">× {cart.get(med.id!)?.quantity}</span>}
                  </div>
                  <div className="flex gap-4 mt-1 opacity-70">
                    <span className="text-xs font-bold bg-emerald-100 px-2 py-0.5 rounded-lg">{med.barcode || 'N/A'}</span>
                    <span className={`text-xs font-bold ${med.stock < 10 ? 'text-red-600' : 'text-emerald-700'}`}>المخزن: {med.stock}</span>
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-2xl font-black text-emerald-700">{med.price.toFixed(2)}</div>
                  <div className="text-[10px] font-bold text-emerald-400">ج.م</div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="space-y-4 animate-in fade-in duration-300">
            <div className="flex bg-white p-1 rounded-2xl shadow-sm sticky top-0 z-10">
              <button onClick={() => setAccountingSubView('sales')} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${accountingSubView === 'sales' ? 'bg-emerald-600 text-white shadow-md' : 'text-emerald-600'}`}> <History size={18} /> المبيعات </button>
              <button onClick={() => setAccountingSubView('inventory')} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${accountingSubView === 'inventory' ? 'bg-emerald-600 text-white shadow-md' : 'text-emerald-600'}`}> <Package size={18} /> المخزون </button>
            </div>

            {accountingSubView === 'sales' ? (
              <div className="space-y-4">
                {/* Sales Filters */}
                <div className="bg-white p-4 rounded-3xl shadow-sm space-y-3">
                  <div className="flex gap-2">
                    <div className="flex-1 flex flex-col gap-1">
                      <label className="text-[10px] font-black text-emerald-900/40 mr-2 uppercase">التاريخ</label>
                      <input type="date" className="bg-emerald-50 p-3 rounded-xl font-bold text-xs border-none outline-none w-full" value={salesDateFilter} onChange={e => setSalesDateFilter(e.target.value)} />
                    </div>
                    <div className="flex-1 flex flex-col gap-1">
                      <label className="text-[10px] font-black text-emerald-900/40 mr-2 uppercase">طريقة الدفع</label>
                      <select className="bg-emerald-50 p-3 rounded-xl font-bold text-xs border-none outline-none w-full" value={salesPaymentFilter} onChange={e => setSalesPaymentFilter(e.target.value as any)}>
                        <option value="all">الكل</option>
                        <option value="cash">كاش</option>
                        <option value="bank">بنك</option>
                        <option value="credit">آجل</option>
                      </select>
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                   <div className="bg-white p-4 rounded-3xl shadow-sm border-b-4 border-emerald-500">
                      <div className="flex items-center gap-1 text-emerald-600 mb-1 text-xs font-bold"> <TrendingUp size={14}/> المبيعات </div>
                      <div className="text-2xl font-black text-emerald-900">{salesStats.revenue.toFixed(2)}</div>
                   </div>
                   <div className="bg-white p-4 rounded-3xl shadow-sm border-b-4 border-amber-500">
                      <div className="flex items-center gap-1 text-amber-600 mb-1 text-xs font-bold"> <Coins size={14}/> الربح </div>
                      <div className="text-2xl font-black text-emerald-900">{salesStats.profit.toFixed(2)}</div>
                   </div>
                </div>

                <div className="space-y-2">
                    {filteredSales.map(sale => (
                        <div key={sale.id} className="bg-white p-4 rounded-2xl shadow-sm border-r-4" style={{borderRightColor: sale.paymentMethod === 'cash' ? '#10b981' : sale.paymentMethod === 'bank' ? '#3b82f6' : '#f59e0b'}}>
                            <div className="flex justify-between items-start mb-2">
                                <div>
                                    <div className="font-black text-lg text-emerald-900">{sale.totalAmount.toFixed(2)} ج.م</div>
                                    <div className="text-[10px] text-emerald-500 font-bold">{formatTime(sale.timestamp)} - {sale.paymentMethod === 'cash' ? 'كاش' : sale.paymentMethod === 'bank' ? 'بنك' : 'آجل'}</div>
                                </div>
                                <div className="text-[10px] font-bold bg-emerald-50 px-2 py-1 rounded-lg text-emerald-700">{formatDate(new Date(sale.timestamp).toISOString())}</div>
                            </div>
                            <div className="text-[11px] text-gray-500 leading-relaxed bg-gray-50 p-2 rounded-xl">
                                {JSON.parse(sale.itemsJson).map((i:any, idx:number) => (
                                    <span key={idx}>{i.name} (×{i.qty}){idx < JSON.parse(sale.itemsJson).length - 1 ? '، ' : ''}</span>
                                ))}
                            </div>
                        </div>
                    ))}
                    {filteredSales.length === 0 && <div className="text-center p-10 text-emerald-200 font-bold italic">لا توجد مبيعات تطابق البحث</div>}
                </div>
              </div>
            ) : (
              <div className="space-y-4">
                {/* Advanced Inventory Filters */}
                <div className="bg-white p-4 rounded-3xl shadow-sm space-y-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-emerald-900/40 uppercase ml-2 flex items-center gap-1"><Tag size={12}/> الفئة</label>
                    <div className="flex overflow-x-auto gap-2 pb-1 no-scrollbar">
                      <button onClick={() => setInvCategoryFilter('all')} className={`px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all ${invCategoryFilter === 'all' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-emerald-50 text-emerald-600'}`}>الكل</button>
                      {categories.map(cat => <button key={cat} onClick={() => setInvCategoryFilter(cat)} className={`px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all ${invCategoryFilter === cat ? 'bg-emerald-600 text-white shadow-lg' : 'bg-emerald-50 text-emerald-600'}`}>{cat}</button>)}
                    </div>
                  </div>

                  <div className="flex gap-4">
                    <div className="flex-1 space-y-2">
                      <label className="text-[10px] font-black text-emerald-900/40 uppercase ml-2 flex items-center gap-1"><Package size={12}/> الكمية</label>
                      <select className="w-full bg-emerald-50 p-3 rounded-xl font-bold text-xs outline-none" value={invStockFilter} onChange={e => setInvStockFilter(e.target.value as any)}>
                        <option value="all">الكل</option>
                        <option value="low">نواقص (&lt;10)</option>
                        <option value="out">منتهي (0)</option>
                      </select>
                    </div>
                    <div className="flex-1 space-y-2">
                      <label className="text-[10px] font-black text-emerald-900/40 uppercase ml-2 flex items-center gap-1"><Calendar size={12}/> الصلاحية</label>
                      <select className="w-full bg-emerald-50 p-3 rounded-xl font-bold text-xs outline-none" value={invExpiryFilter} onChange={e => setInvExpiryFilter(e.target.value as any)}>
                        <option value="all">الكل</option>
                        <option value="soon">قريبة (&lt;3 شهور)</option>
                        <option value="expired">منتهية</option>
                      </select>
                    </div>
                  </div>
                </div>

                <div className="space-y-2">
                  {filteredInventory.map(med => {
                    const isExpired = new Date(med.expiryDate) <= new Date();
                    const isLow = med.stock <= 5;
                    return (
                      <div key={med.id} onClick={() => { setEditingMedicine(med); setIsEditOpen(true); }} className="bg-white p-4 rounded-2xl flex justify-between items-center shadow-sm border-r-8" style={{ borderRightColor: isExpired ? '#ef4444' : isLow ? '#f59e0b' : '#10b981' }}>
                        <div>
                          <div className="font-bold text-emerald-900">{med.name}</div>
                          <div className="text-[10px] text-emerald-500 font-bold">{med.category} • تنتهي: {formatDate(med.expiryDate)}</div>
                        </div>
                        <div className="text-right">
                          <div className={`font-black ${med.stock < 5 ? 'text-red-500' : 'text-emerald-700'}`}>{med.stock} <span className="text-[9px] font-normal opacity-50">ق قطعة</span></div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {/* POS Cart Control */}
      {view === 'pos' && cart.size > 0 && (
        <div className="fixed bottom-24 left-0 right-0 p-4 pointer-events-none z-50">
            <div className="max-w-md mx-auto bg-emerald-900/95 backdrop-blur-xl text-white p-5 rounded-[40px] shadow-2xl pointer-events-auto border border-white/10">
                {/* Payment Selector */}
                <div className="flex gap-2 mb-4 bg-white/5 p-1 rounded-2xl">
                    <button onClick={() => setSelectedPayment('cash')} className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-xl text-[10px] font-black transition-all ${selectedPayment === 'cash' ? 'bg-emerald-500 text-white' : 'text-emerald-400'}`}> <Wallet size={14}/> كاش </button>
                    <button onClick={() => setSelectedPayment('bank')} className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-xl text-[10px] font-black transition-all ${selectedPayment === 'bank' ? 'bg-blue-500 text-white' : 'text-emerald-400'}`}> <CreditCard size={14}/> بنك </button>
                    <button onClick={() => setSelectedPayment('credit')} className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-xl text-[10px] font-black transition-all ${selectedPayment === 'credit' ? 'bg-amber-500 text-white' : 'text-emerald-400'}`}> <UserMinus size={14}/> آجل </button>
                </div>

                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <button onClick={clearCart} className="bg-red-500/20 text-red-400 p-3 rounded-2xl"><Trash2 size={24} /></button>
                        <div>
                            <div className="text-2xl font-black">{cartTotal.toFixed(2)} <span className="text-xs font-normal">ج.م</span></div>
                            <div className="text-[10px] font-bold opacity-40">{cartItemsCount} قطعة مختارة</div>
                        </div>
                    </div>
                    <button onClick={handleCheckout} className="bg-emerald-500 text-white px-8 py-4 rounded-[24px] font-black text-xl shadow-lg active:scale-95 transition-all">تأكيد </button>
                </div>
            </div>
        </div>
      )}

      {checkoutResult && (
